{
  "name": "Generator RPM SDN Pekayon 09",
  "description": "Aplikasi generator Perencanaan Pembelajaran Mendalam (RPM) otomatis menggunakan AI untuk guru SDN Pekayon 09."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum ClassLevel {
  Kelas1 = "1",
  Kelas2 = "2",
  Kelas3 = "3",
  Kelas4 = "4",
  Kelas5 = "5",
  Kelas6 = "6"
}

export enum Semester {
  Ganjil = "Ganjil",
  Genap = "Genap"
}

export enum Subject {
  PAI = "Pendidikan Agama Islam",
  Pancasila = "Pendidikan Pancasila",
  BahasaIndonesia = "Bahasa Indonesia",
  IPAS = "IPAS",
  Matematika = "Matematika",
  SeniBudaya = "Seni Budaya",
  BahasaInggris = "Bahasa Inggris",
  PLBJ = "PLBJ",
  PJOK = "PJOK"
}

export enum PedagogicalPractice {
  InkuiriDiscovery = "Inkuiri-Discovery Learning",
  PjBL = "Project Based Learning (PjBL)",
  ProblemSolving = "Problem Based Learning (PBL)",
  GameBased = "Game Based Learning",
  Station = "Station Learning"
}

export enum GraduateDimension {
  Keimanan = "Keimanan & Ketakwaan",
  Kewargaan = "Kewargaan",
  Kritis = "Penalaran Kritis",
  Kreativitas = "Kreativitas",
  Kolaborasi = "Kolaborasi",
  Kemandirian = "Kemandirian",
  Kesehatan = "Kesehatan",
  Komunikasi = "Komunikasi"
}

export interface MeetingPlan {
  meetingNumber: number;
  pedagogy: PedagogicalPractice;
}

export interface FormData {
  teacherName: string;
  teacherNIP: string;
  principalName: string; // Default: Veria Wulandari
  principalNIP: string; // Default: 198102012008012028
  classLevel: ClassLevel;
  semester: Semester;
  subject: Subject;
  cp: string;
  tp: string;
  materi: string;
  meetingCount: number;
  duration: string;
  meetings: MeetingPlan[];
  dimensions: GraduateDimension[];
}

export interface GeneratedContent {
  studentCharacteristics: string;
  crossDisciplinary: string;
  topics: string;
  partnerships: string;
  environment: string;
  digitalTools: string;
  learningExperiences: {
    memahami: string;
    mengaplikasi: string;
    refleksi: string;
  };
  assessments: {
    initial: string;
    process: string;
    final: string;
  };
}

export interface RPMResult extends FormData, GeneratedContent {}

import { GoogleGenAI, Type, Schema } from "@google/genai";
import { FormData, GeneratedContent } from "../types";

const apiKey = process.env.API_KEY || "";
const ai = new GoogleGenAI({ apiKey });

const generatedContentSchema: Schema = {
  type: Type.OBJECT,
  properties: {
    studentCharacteristics: { type: Type.STRING, description: "Description of student characteristics based on age/class" },
    crossDisciplinary: { type: Type.STRING, description: "Connection to other subjects" },
    topics: { type: Type.STRING, description: "Specific learning topics derived from material" },
    partnerships: { type: Type.STRING, description: "Learning partnerships (parents, experts, community)" },
    environment: { type: Type.STRING, description: "Learning environment setup" },
    digitalTools: { type: Type.STRING, description: "Recommended digital tools and how to use them" },
    learningExperiences: {
      type: Type.OBJECT,
      properties: {
        memahami: { type: Type.STRING, description: "Activity for 'Memahami' phase (Opening)" },
        mengaplikasi: { type: Type.STRING, description: "Activity for 'Mengaplikasi' phase (Core) matching the pedagogy syntax" },
        refleksi: { type: Type.STRING, description: "Activity for 'Refleksi' phase (Closing)" },
      },
      required: ["memahami", "mengaplikasi", "refleksi"]
    },
    assessments: {
      type: Type.OBJECT,
      properties: {
        initial: { type: Type.STRING, description: "Diagnostic assessment ideas" },
        process: { type: Type.STRING, description: "Formative assessment (rubric, observation)" },
        final: { type: Type.STRING, description: "Summative assessment (product, portfolio)" },
      },
      required: ["initial", "process", "final"]
    }
  },
  required: ["studentCharacteristics", "crossDisciplinary", "topics", "partnerships", "environment", "digitalTools", "learningExperiences", "assessments"]
};

export const generateRPM = async (data: FormData): Promise<GeneratedContent> => {
  const pedagogies = data.meetings.map(m => `Pertemuan ${m.meetingNumber}: ${m.pedagogy}`).join(", ");
  const dimensions = data.dimensions.join(", ");

  const prompt = `
    Bertindaklah sebagai ahli kurikulum SD Indonesia. Buatlah konten Rencana Pembelajaran Mendalam (RPM) untuk SDN Pekayon 09.

    Data Input:
    - Kelas: ${data.classLevel}
    - Mapel: ${data.subject}
    - Materi: ${data.materi}
    - CP: ${data.cp}
    - TP: ${data.tp}
    - Dimensi Profil Pelajar: ${dimensions}
    - Praktik Pedagogis per Pertemuan: ${pedagogies}

    Tugas:
    Lengkapi bagian-bagian rencana pembelajaran yang kosong berikut ini dengan bahasa Indonesia yang formal, edukatif, namun aplikatif:
    1. Karakteristik Siswa (Siswa): Deskripsikan karakteristik umum siswa kelas ${data.classLevel} SD.
    2. Lintas Disiplin Ilmu: Hubungkan materi ini dengan mata pelajaran lain.
    3. Topik Pembelajaran: Breakdown materi menjadi topik spesifik.
    4. Kemitraan: Siapa yang bisa dilibatkan?
    5. Lingkungan: Bagaimana setting kelas/luar kelas?
    6. Digital: Rekomendasi tools spesifik (misal: Quizizz, Canva, Youtube, dll).
    7. Pengalaman Belajar:
       - Memahami (Awal): Kegiatan pemantik yang 'berkesadaran/bermakna/menggembirakan'.
       - Mengaplikasi (Inti): Rangkaian kegiatan inti yang SANGAT SESUAI dengan sintaks ${pedagogies}. Jika ada beda pedagogi tiap pertemuan, gabungkan narasi sintaksnya secara ringkas.
       - Refleksi (Penutup): Kegiatan penutup.
    8. Asesmen: Awal, Proses, dan Akhir.
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: generatedContentSchema,
      }
    });

    const result = JSON.parse(response.text || "{}");
    return result as GeneratedContent;
  } catch (error) {
    console.error("Error generating RPM:", error);
    throw new Error("Gagal membuat rencana pembelajaran. Silakan coba lagi.");
  }
};

export const suggestPlanningData = async (subject: string, classLevel: string) => {
  const prompt = `
    Berikan saran Capaian Pembelajaran (CP), Tujuan Pembelajaran (TP), dan Materi Pokok untuk mata pelajaran ${subject} Kelas ${classLevel} SD Kurikulum Merdeka.
    Format JSON: { "cp": "...", "tp": "...", "materi": "..." }
  `;

  try {
     const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        responseMimeType: "application/json"
      }
    });
    return JSON.parse(response.text || "{}");
  } catch (e) {
    return { cp: "", tp: "", materi: "" };
  }
}

import React, { useState, useEffect } from 'react';
import { 
  ClassLevel, Semester, Subject, PedagogicalPractice, 
  GraduateDimension, FormData, MeetingPlan 
} from '../types';
import { suggestPlanningData } from '../services/geminiService';
import { Sparkles, Loader2, BookOpen, User, Calendar, CheckCircle } from 'lucide-react';

interface InputFormProps {
  onSubmit: (data: FormData) => void;
  isLoading: boolean;
}

const InputForm: React.FC<InputFormProps> = ({ onSubmit, isLoading }) => {
  const [formData, setFormData] = useState<FormData>({
    teacherName: '',
    teacherNIP: '',
    principalName: 'Veria Wulandari',
    principalNIP: '198102012008012028',
    classLevel: ClassLevel.Kelas1,
    semester: Semester.Ganjil,
    subject: Subject.BahasaIndonesia,
    cp: '',
    tp: '',
    materi: '',
    meetingCount: 1,
    duration: '2 x 35 menit',
    meetings: [{ meetingNumber: 1, pedagogy: PedagogicalPractice.InkuiriDiscovery }],
    dimensions: []
  });

  const [isSuggesting, setIsSuggesting] = useState(false);

  // Update meetings array when count changes
  useEffect(() => {
    setFormData(prev => {
      const currentCount = prev.meetings.length;
      const targetCount = prev.meetingCount;

      if (currentCount === targetCount) return prev;

      let newMeetings = [...prev.meetings];
      if (targetCount > currentCount) {
        for (let i = currentCount + 1; i <= targetCount; i++) {
          newMeetings.push({ meetingNumber: i, pedagogy: PedagogicalPractice.InkuiriDiscovery });
        }
      } else {
        newMeetings = newMeetings.slice(0, targetCount);
      }
      return { ...prev, meetings: newMeetings };
    });
  }, [formData.meetingCount]);

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement | HTMLTextAreaElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  const handleDimensionChange = (dim: GraduateDimension) => {
    setFormData(prev => {
      const exists = prev.dimensions.includes(dim);
      if (exists) {
        return { ...prev, dimensions: prev.dimensions.filter(d => d !== dim) };
      } else {
        return { ...prev, dimensions: [...prev.dimensions, dim] };
      }
    });
  };

  const handlePedagogyChange = (index: number, value: PedagogicalPractice) => {
    const newMeetings = [...formData.meetings];
    newMeetings[index].pedagogy = value;
    setFormData(prev => ({ ...prev, meetings: newMeetings }));
  };

  const handleSuggest = async () => {
    setIsSuggesting(true);
    const suggestion = await suggestPlanningData(formData.subject, formData.classLevel);
    setFormData(prev => ({
      ...prev,
      cp: suggestion.cp || prev.cp,
      tp: suggestion.tp || prev.tp,
      materi: suggestion.materi || prev.materi
    }));
    setIsSuggesting(false);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onSubmit(formData);
  };

  return (
    <form onSubmit={handleSubmit} className="bg-white p-6 md:p-8 rounded-2xl shadow-xl border border-slate-100 max-w-4xl mx-auto space-y-8">

      {/* Header Section */}
      <div className="text-center border-b border-slate-100 pb-6">
        <h2 className="text-2xl font-bold text-teal-700 font-comic">Formulir RPM</h2>
        <p className="text-slate-500 text-sm mt-1">Isi data di bawah ini untuk men-generate rencana pembelajaran.</p>
      </div>

      {/* Identitas Guru & Sekolah */}
      <section className="space-y-4">
        <div className="flex items-center gap-2 text-teal-600 font-semibold border-b pb-2">
          <User size={20} /> <h3>Identitas Pendidik</h3>
        </div>
        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
          <div>
            <label className="block text-sm font-medium text-slate-700 mb-1">Nama Satuan Pendidikan</label>
            <input type="text" value="SDN Pekayon 09" disabled className="w-full p-2 bg-slate-100 border border-slate-300 rounded-lg text-slate-500" />
          </div>
          <div>
             {/* Empty for layout balance or maybe Logo */}
          </div>
          <div>
            <label className="block text-sm font-medium text-slate-700 mb-1">Nama Guru <span className="text-red-500">*</span></label>
            <input required name="teacherName" value={formData.teacherName} onChange={handleChange} className="w-full p-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-teal-500 outline-none" placeholder="Contoh: Budi Santoso, S.Pd" />
          </div>
          <div>
            <label className="block text-sm font-medium text-slate-700 mb-1">NIP Guru <span className="text-red-500">*</span></label>
            <input required name="teacherNIP" value={formData.teacherNIP} onChange={handleChange} className="w-full p-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-teal-500 outline-none" placeholder="198xxxxxxx" />
          </div>
          <div>
            <label className="block text-sm font-medium text-slate-700 mb-1">Nama Kepala Sekolah</label>
            <input name="principalName" value={formData.principalName} onChange={handleChange} className="w-full p-2 border border-slate-300 rounded-lg bg-slate-50" />
          </div>
          <div>
            <label className="block text-sm font-medium text-slate-700 mb-1">NIP Kepala Sekolah</label>
            <input name="principalNIP" value={formData.principalNIP} onChange={handleChange} className="w-full p-2 border border-slate-300 rounded-lg bg-slate-50" />
          </div>
        </div>
      </section>

      {/* Informasi Pembelajaran */}
      <section className="space-y-4">
        <div className="flex items-center gap-2 text-teal-600 font-semibold border-b pb-2">
          <BookOpen size={20} /> <h3>Informasi Kelas & Mapel</h3>
        </div>
        <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
          <div>
            <label className="block text-sm font-medium text-slate-700 mb-1">Kelas</label>
            <select name="classLevel" value={formData.classLevel} onChange={handleChange} className="w-full p-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-teal-500">
              {Object.values(ClassLevel).map(c => <option key={c} value={c}>Kelas {c}</option>)}
            </select>
          </div>
          <div>
            <label className="block text-sm font-medium text-slate-700 mb-1">Semester</label>
            <select name="semester" value={formData.semester} onChange={handleChange} className="w-full p-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-teal-500">
              {Object.values(Semester).map(s => <option key={s} value={s}>{s}</option>)}
            </select>
          </div>
          <div>
            <label className="block text-sm font-medium text-slate-700 mb-1">Mata Pelajaran</label>
            <select name="subject" value={formData.subject} onChange={handleChange} className="w-full p-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-teal-500">
              {Object.values(Subject).map(s => <option key={s} value={s}>{s}</option>)}
            </select>
          </div>
        </div>

        {/* AI Suggestion Button */}
        <div className="bg-orange-50 p-4 rounded-lg border border-orange-100">
          <div className="flex justify-between items-center mb-2">
             <h4 className="text-orange-800 font-medium text-sm">Bantuan Konten AI</h4>
             <button type="button" onClick={handleSuggest} disabled={isSuggesting} className="flex items-center gap-2 text-xs bg-orange-500 hover:bg-orange-600 text-white px-3 py-1.5 rounded-full transition">
               {isSuggesting ? <Loader2 className="animate-spin" size={14} /> : <Sparkles size={14} />}
               {isSuggesting ? 'Sedang mencari...' : 'Saran CP, TP, Materi'}
             </button>
          </div>
          <p className="text-xs text-orange-600/80 mb-3">Klik tombol di atas untuk mengisi CP, TP, dan Materi secara otomatis berdasarkan Mapel dan Kelas.</p>

          <div className="space-y-3">
             <div>
                <label className="block text-xs font-semibold text-slate-600 mb-1">Capaian Pembelajaran (CP)</label>
                <textarea required name="cp" value={formData.cp} onChange={handleChange} rows={3} className="w-full p-2 text-sm border border-slate-300 rounded-lg focus:ring-2 focus:ring-orange-300 outline-none" placeholder="Masukan CP..." />
             </div>
             <div>
                <label className="block text-xs font-semibold text-slate-600 mb-1">Tujuan Pembelajaran (TP)</label>
                <textarea required name="tp" value={formData.tp} onChange={handleChange} rows={2} className="w-full p-2 text-sm border border-slate-300 rounded-lg focus:ring-2 focus:ring-orange-300 outline-none" placeholder="Masukan TP..." />
             </div>
             <div>
                <label className="block text-xs font-semibold text-slate-600 mb-1">Materi Pelajaran</label>
                <textarea required name="materi" value={formData.materi} onChange={handleChange} rows={2} className="w-full p-2 text-sm border border-slate-300 rounded-lg focus:ring-2 focus:ring-orange-300 outline-none" placeholder="Masukan Materi..." />
             </div>
          </div>
        </div>
      </section>

      {/* Detil Pertemuan */}
      <section className="space-y-4">
        <div className="flex items-center gap-2 text-teal-600 font-semibold border-b pb-2">
          <Calendar size={20} /> <h3>Detail Pertemuan</h3>
        </div>
        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
           <div>
            <label className="block text-sm font-medium text-slate-700 mb-1">Jumlah Pertemuan</label>
            <select name="meetingCount" value={formData.meetingCount} onChange={(e) => setFormData({...formData, meetingCount: parseInt(e.target.value)})} className="w-full p-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-teal-500">
              {[1, 2, 3, 4, 5, 6, 7, 8].map(n => <option key={n} value={n}>{n} Pertemuan</option>)}
            </select>
           </div>
           <div>
            <label className="block text-sm font-medium text-slate-700 mb-1">Durasi per Pertemuan</label>
            <input name="duration" value={formData.duration} onChange={handleChange} className="w-full p-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-teal-500" placeholder="contoh: 2 x 35 menit" />
           </div>
        </div>

        <div className="space-y-2 mt-4">
           <label className="block text-sm font-medium text-slate-700">Praktik Pedagogis per Pertemuan</label>
           {formData.meetings.map((meeting, idx) => (
             <div key={idx} className="flex items-center gap-3 bg-slate-50 p-2 rounded border border-slate-200">
                <span className="text-sm font-semibold text-teal-700 w-24">Pertemuan {meeting.meetingNumber}</span>
                <select 
                  value={meeting.pedagogy} 
                  onChange={(e) => handlePedagogyChange(idx, e.target.value as PedagogicalPractice)}
                  className="flex-1 p-1.5 text-sm border border-slate-300 rounded focus:ring-1 focus:ring-teal-500"
                >
                  {Object.values(PedagogicalPractice).map(p => <option key={p} value={p}>{p}</option>)}
                </select>
             </div>
           ))}
        </div>
      </section>

      {/* Dimensi Lulusan */}
      <section className="space-y-4">
        <div className="flex items-center gap-2 text-teal-600 font-semibold border-b pb-2">
          <CheckCircle size={20} /> <h3>Dimensi Lulusan (Pilih yang relevan)</h3>
        </div>
        <div className="grid grid-cols-2 md:grid-cols-4 gap-3">
           {Object.values(GraduateDimension).map((dim) => (
             <label key={dim} className={`flex items-center gap-2 p-3 rounded-lg border cursor-pointer transition-all ${formData.dimensions.includes(dim) ? 'bg-teal-50 border-teal-500 text-teal-800' : 'bg-white border-slate-200 text-slate-600 hover:bg-slate-50'}`}>
                <input type="checkbox" checked={formData.dimensions.includes(dim)} onChange={() => handleDimensionChange(dim)} className="rounded text-teal-600 focus:ring-teal-500" />
                <span className="text-xs font-medium leading-tight">{dim}</span>
             </label>
           ))}
        </div>
      </section>

      {/* Submit Button */}
      <div className="pt-4">
        <button 
          type="submit" 
          disabled={isLoading}
          className="w-full bg-gradient-to-r from-teal-500 to-emerald-600 text-white font-bold py-4 rounded-xl shadow-lg hover:shadow-xl transform transition hover:-translate-y-0.5 disabled:opacity-70 disabled:cursor-not-allowed flex justify-center items-center gap-2"
        >
          {isLoading ? (
            <>
              <Loader2 className="animate-spin" /> Sedang Membuat RPM...
            </>
          ) : (
            <>
              <Sparkles className="text-yellow-300" /> Buat Rencana Pembelajaran Mendalam
            </>
          )}
        </button>
      </div>
    </form>
  );
};

export default InputForm;

import React, { useRef } from 'react';
import { RPMResult } from '../types';
import { Copy, Download, ArrowLeft, ExternalLink } from 'lucide-react';
// @ts-ignore
import html2pdf from 'html2pdf.js';

interface RPMPreviewProps {
  data: RPMResult;
  onReset: () => void;
}

const RPMPreview: React.FC<RPMPreviewProps> = ({ data, onReset }) => {
  const contentRef = useRef<HTMLDivElement>(null);

  const handleCopyToDocs = async () => {
    if (!contentRef.current) return;

    try {
      // Basic clipboard copy of the inner HTML
      // Note: Full formatting preservation is hard without native Clipboard Item API support for text/html
      // We instruct user to paste.
      const blob = new Blob([contentRef.current.innerHTML], { type: 'text/html' });
      const clipboardItem = new ClipboardItem({ 'text/html': blob });
      await navigator.clipboard.write([clipboardItem]);

      const confirm = window.confirm("Konten RPM telah disalin ke Clipboard! \n\nSekarang kami akan membuka Google Docs baru. \nSilakan tekan 'Ctrl+V' (Paste) di halaman Google Docs yang terbuka untuk melihat hasilnya.");

      if(confirm) {
        window.open('https://docs.google.com/document/create', '_blank');
      }
    } catch (err) {
      console.error(err);
      alert('Gagal menyalin otomatis. Silakan seleksi manual dan salin.');
    }
  };

  const handleDownloadPDF = () => {
    const element = contentRef.current;
    const opt = {
      margin:       10,
      filename:     `RPM_${data.subject}_Kelas${data.classLevel}.pdf`,
      image:        { type: 'jpeg', quality: 0.98 },
      html2canvas:  { scale: 2 },
      jsPDF:        { unit: 'mm', format: 'a4', orientation: 'portrait' }
    };

    html2pdf().set(opt).from(element).save();
  };

  return (
    <div className="max-w-5xl mx-auto pb-20">
      {/* Action Bar */}
      <div className="sticky top-4 z-50 flex flex-wrap gap-3 justify-between items-center bg-white/90 backdrop-blur p-4 rounded-xl shadow-lg border border-slate-200 mb-8 no-print">
        <button onClick={onReset} className="flex items-center gap-2 text-slate-600 hover:text-slate-900 font-medium transition">
          <ArrowLeft size={18} /> Edit Data
        </button>
        <div className="flex gap-3">
          <button onClick={handleCopyToDocs} className="flex items-center gap-2 bg-blue-50 text-blue-700 hover:bg-blue-100 px-4 py-2 rounded-lg font-medium transition border border-blue-200">
            <Copy size={18} />
            <span className="hidden sm:inline">Salin & Buka G-Docs</span>
          </button>
          <button onClick={handleDownloadPDF} className="flex items-center gap-2 bg-red-50 text-red-700 hover:bg-red-100 px-4 py-2 rounded-lg font-medium transition border border-red-200">
            <Download size={18} />
            <span className="hidden sm:inline">Download PDF</span>
          </button>
        </div>
      </div>

      {/* Document Content - Styled for "Print/Spreadsheet" look */}
      <div id="rpm-content" ref={contentRef} className="bg-white p-8 md:p-12 shadow-2xl min-h-screen text-black">
        <style>
            {`
              table { width: 100%; border-collapse: collapse; margin-bottom: 20px; font-size: 11pt; }
              th, td { border: 1px solid black; padding: 8px; vertical-align: top; text-align: left; }
              th { background-color: #f0f0f0; font-weight: bold; text-align: center; }
              .section-title { background-color: #d1fae5; font-weight: bold; font-size: 12pt; text-transform: uppercase; padding: 10px; border: 1px solid black; margin-top: 10px; }
