            <input required name="teacherNIP" value={formData.teacherNIP} onChange={handleChange} className="w-full p-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-teal-500 outline-none" placeholder="198xxxxxxx" />
          </div>
          <div>
            <label className="block text-sm font-medium text-slate-700 mb-1">Nama Kepala Sekolah</label>
            <input name="principalName" value={formData.principalName} onChange={handleChange} className="w-full p-2 border border-slate-300 rounded-lg bg-slate-50" />
