            `}
        </style>

        <div style={{ textAlign: 'center', marginBottom: '15px' }}>
           <img src="https://i.ibb.co.com/1fQ81J6v/LOGO-PEKAYON-09.jpg" alt="Logo SDN Pekayon 09" style={{ height: '100px', width: 'auto' }} />
        </div>

        <h1 style={{ textAlign: 'center', fontWeight: 'bold', fontSize: '16pt', marginBottom: '20px', textTransform: 'uppercase' }}>
