        {/* 4. Pengalaman Belajar */}
        <div className="section-title">4. PENGALAMAN BELAJAR</div>
        <table>
          <thead>
            <tr>
              <th style={{ width: '20%' }}>Tahapan</th>
              <th style={{ width: '80%' }}>Deskripsi Kegiatan</th>
            </tr>
          </thead>
          <tbody>
            <tr>
              <td className="sub-title">Memahami (Awal)</td>
