        </table>

        {/* Signatures */}
        <div className="signature-box" style={{ display: 'flex', justifyContent: 'space-between', marginTop: '60px' }}>
            <div style={{ textAlign: 'left', width: '40%' }}>
                <p>Mengetahui,</p>
                <p>Kepala SDN Pekayon 09</p>
                <br/><br/><br/>
                <p style={{ fontWeight: 'bold', textDecoration: 'underline' }}>{data.principalName}</p>
