              .sub-title { font-weight: bold; }
              .text-center { text-align: center; }
              .no-border-bottom { border-bottom: none; }
              .no-border-top { border-top: none; }
              .signature-box { margin-top: 50px; page-break-inside: avoid; }
              /* Specific styles for HTML lists from AI */
              ol { list-style-type: decimal; padding-left: 20px; margin: 0; }
              ul { list-style-type: disc; padding-left: 20px; margin: 0; }
              li { margin-bottom: 4px; }
            `}
        </style>

        {/* Kop Surat / Header */}
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '20px', paddingBottom: '15px', borderBottom: '3px double black' }}>
            {/* Logo Kiri (Sekolah) */}
            <div style={{ width: '15%', display: 'flex', justifyContent: 'flex-start' }}>
                <img 
                    src="https://i.ibb.co.com/1fQ81J6v/LOGO-PEKAYON-09.jpg" 
                    alt="Logo SDN Pekayon 09" 
                    style={{ height: '90px', width: 'auto' }} 
                />
