import React, { useState, useEffect } from 'react';
import { 
  ClassLevel, Semester, Subject, PedagogicalPractice, 
  GraduateDimension, FormData
} from '../types';
import { getFieldSuggestions } from '../services/geminiService';
import { Sparkles, Loader2, BookOpen, User, Calendar, CheckCircle, X, CheckSquare, Square } from 'lucide-react';

interface InputFormProps {
  onSubmit: (data: FormData) => void;
  isLoading: boolean;
}

const InputForm: React.FC<InputFormProps> = ({ onSubmit, isLoading }) => {
  const [formData, setFormData] = useState<FormData>({
    teacherName: '',
    teacherNIP: '',
    principalName: 'Veria Wulandari,S.Pd',
    principalNIP: '198102012008012028',
    classLevel: ClassLevel.Kelas1,
    semester: Semester.Ganjil,
    subject: Subject.BahasaIndonesia,
    cp: '',
    tp: '',
    materi: '',
    meetingCount: 1,
    duration: '2 x 35 menit',
    meetings: [{ meetingNumber: 1, pedagogy: PedagogicalPractice.InkuiriDiscovery }],
    dimensions: []
  });

  const [suggestions, setSuggestions] = useState<string[]>([]);
  const [activeField, setActiveField] = useState<'cp' | 'tp' | 'materi' | null>(null);
  const [loadingField, setLoadingField] = useState<'cp' | 'tp' | 'materi' | null>(null);
  const [selectedSuggestions, setSelectedSuggestions] = useState<string[]>([]);

  // Update meetings array when count changes
  useEffect(() => {
    setFormData(prev => {
      const currentCount = prev.meetings.length;
      const targetCount = prev.meetingCount;

      if (currentCount === targetCount) return prev;

      let newMeetings = [...prev.meetings];
      if (targetCount > currentCount) {
        for (let i = currentCount + 1; i <= targetCount; i++) {
          newMeetings.push({ meetingNumber: i, pedagogy: PedagogicalPractice.InkuiriDiscovery });
        }
      } else {
        newMeetings = newMeetings.slice(0, targetCount);
      }
      return { ...prev, meetings: newMeetings };
    });
  }, [formData.meetingCount]);

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement | HTMLTextAreaElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  const handleDimensionChange = (dim: GraduateDimension) => {
    setFormData(prev => {
      const exists = prev.dimensions.includes(dim);
      if (exists) {
        return { ...prev, dimensions: prev.dimensions.filter(d => d !== dim) };
      } else {
        return { ...prev, dimensions: [...prev.dimensions, dim] };
      }
    });
  };

  const handlePedagogyChange = (index: number, value: PedagogicalPractice) => {
    const newMeetings = [...formData.meetings];
    newMeetings[index].pedagogy = value;
    setFormData(prev => ({ ...prev, meetings: newMeetings }));
  };

  const handleGetSuggestion = async (field: 'cp' | 'tp' | 'materi') => {
    setLoadingField(field);
    setSuggestions([]);
    setSelectedSuggestions([]); // Reset selections
    setActiveField(null);

    // Determine context for the suggestion
    let context = "";
    if (field === 'tp') {
        // If asking for TP, pass the current CP as context
        context = formData.cp;
    } else if (field === 'materi') {
        // If asking for Materi, pass CP + TP
        context = `CP: ${formData.cp}. TP: ${formData.tp}`;
    }

    const opts = await getFieldSuggestions(field, formData.subject, formData.classLevel, context);

    setSuggestions(opts);
    setActiveField(field);
    setLoadingField(null);
  };

  // Handle single click selection (for CP)
  const handleSelectSuggestion = (val: string) => {
    if (activeField) {
        setFormData(prev => ({ ...prev, [activeField]: val }));
        setActiveField(null);
        setSuggestions([]);
        setSelectedSuggestions([]);
    }
  };

  // Handle toggle selection (for TP and Materi checkbox)
  const handleToggleSuggestion = (val: string) => {
    setSelectedSuggestions(prev => {
      if (prev.includes(val)) {
        return prev.filter(item => item !== val);
      } else {
        return [...prev, val];
      }
    });
  };

  // Apply multiple selected suggestions
  const handleApplySelected = () => {
    if (activeField && selectedSuggestions.length > 0) {
      // Join selected items with newline
      const joinedValue = selectedSuggestions.join('\n');
      setFormData(prev => ({ ...prev, [activeField]: joinedValue }));
      setActiveField(null);
      setSuggestions([]);
      setSelectedSuggestions([]);
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onSubmit(formData);
  };

  const renderSuggestionInput = (field: 'cp' | 'tp' | 'materi', label: string, rows: number, placeholder: string) => {
    // TP and Materi use multi-select checkbox logic
    const isMultiSelect = field === 'tp' || field === 'materi';

    return (
      <div className="relative group">
          <div className="flex justify-between items-end mb-1">
               <label className="block text-sm font-semibold text-slate-700">{label}</label>
               <button 
                  type="button" 
                  onClick={() => handleGetSuggestion(field)}
                  disabled={loadingField === field}
                  className="text-xs flex items-center gap-1 bg-teal-50 hover:bg-teal-100 text-teal-700 px-2 py-1 rounded-full font-medium transition-colors"
               >
                  {loadingField === field ? <Loader2 size={12} className="animate-spin" /> : <Sparkles size={12} />}
                  {loadingField === field ? 'Mencari...' : 'Saran AI'}
               </button>
          </div>
          <textarea 
              required 
              name={field} 
              value={formData[field]} 
              onChange={handleChange} 
              rows={rows} 
              className="w-full p-2 text-sm border border-slate-300 rounded-lg focus:ring-2 focus:ring-teal-500 outline-none" 
              placeholder={placeholder} 
          />
          {activeField === field && suggestions.length > 0 && (
              <div className="absolute z-20 w-full bg-white border border-slate-200 shadow-2xl rounded-lg mt-1 max-h-60 flex flex-col animate-fade-in-up">
                   <div className="sticky top-0 bg-slate-50 border-b border-slate-100 p-2 flex justify-between items-center backdrop-blur-sm bg-opacity-90 z-10 rounded-t-lg">
                      <span className="text-xs font-bold text-teal-700">
                        {isMultiSelect ? 'Pilih satu atau lebih:' : `Pilih Saran ${label}:`}
                      </span>
                      <button type="button" onClick={() => setActiveField(null)} className="text-slate-400 hover:text-red-500 transition">
                          <X size={14} />
                      </button>
                   </div>

                   <ul className="overflow-y-auto flex-1">
                      {suggestions.map((s, idx) => {
                          const isSelected = selectedSuggestions.includes(s);
                          return (
                            <li 
                                key={idx} 
                                onClick={() => isMultiSelect ? handleToggleSuggestion(s) : handleSelectSuggestion(s)} 
                                className={`p-3 text-sm border-b border-slate-50 last:border-0 cursor-pointer transition-colors flex items-start gap-3 ${
                                  isSelected ? 'bg-teal-50 text-teal-900' : 'hover:bg-slate-50 text-slate-700'
                                }`}
                            >
                                {isMultiSelect && (
                                  <div className={`mt-0.5 ${isSelected ? 'text-teal-600' : 'text-slate-300'}`}>
                                    {isSelected ? <CheckSquare size={16} /> : <Square size={16} />}
                                  </div>
                                )}
                                <span className="flex-1">{s}</span>
                            </li>
                          );
                      })}
                   </ul>

                   {isMultiSelect && (
                     <div className="sticky bottom-0 p-2 bg-white border-t border-slate-100 rounded-b-lg">
                       <button
                         type="button"
                         onClick={handleApplySelected}
                         disabled={selectedSuggestions.length === 0}
                         className="w-full py-2 bg-teal-600 hover:bg-teal-700 disabled:bg-slate-300 text-white text-sm font-semibold rounded-lg transition-colors"
                       >
                         Gunakan {selectedSuggestions.length > 0 ? `(${selectedSuggestions.length})` : ''} {field === 'tp' ? 'Tujuan Pembelajaran' : 'Materi'}
                       </button>
                     </div>
                   )}
              </div>
          )}
      </div>
    );
  };

  return (
    <form onSubmit={handleSubmit} className="bg-white p-6 md:p-8 rounded-2xl shadow-xl border border-slate-100 max-w-4xl mx-auto space-y-8">

