                    alt="Logo Kemendikbud" 
                    crossOrigin="anonymous"
                    style={{ height: '90px', width: 'auto' }} 
                />
            </div>
        </div>

        {/* 1. Identitas */}
        <div className="section-title">1. IDENTITAS</div>
        <table>
          <tbody>
            <tr>
              <td style={{ width: '25%' }} className="sub-title">Nama Satuan Pendidikan</td>
              <td style={{ width: '25%' }}>SDN Pekayon 09</td>
              <td style={{ width: '25%' }} className="sub-title">Mata Pelajaran</td>
              <td style={{ width: '25%' }}>{data.subject}</td>
