export default RPMPreview;

import { GoogleGenAI, Type, Schema } from "@google/genai";
import { FormData, GeneratedContent, Subject, ClassLevel } from "../types";
import { CP_REF } from "../data/cpReference";

// Helper to create AI instance dynamically
const getAI = (apiKey: string) => new GoogleGenAI({ apiKey });

const generatedContentSchema: Schema = {
  type: Type.OBJECT,
  properties: {
    studentCharacteristics: { type: Type.STRING, description: "Description of student characteristics based on age/class" },
    crossDisciplinary: { type: Type.STRING, description: "Connection to other subjects" },
    topics: { type: Type.STRING, description: "Specific learning topics derived from material" },
    partnerships: { type: Type.STRING, description: "Learning partnerships (parents, experts, community)" },
    environment: { type: Type.STRING, description: "Learning environment setup" },
    digitalTools: { type: Type.STRING, description: "Recommended digital tools and how to use them" },
    learningExperiences: {
      type: Type.OBJECT,
      properties: {
        memahami: { type: Type.STRING, description: "Activity for 'Memahami' phase (Opening). Return as HTML Ordered List (<ol><li>...</li></ol>)." },
        mengaplikasi: { type: Type.STRING, description: "Activity for 'Mengaplikasi' phase (Core) matching the pedagogy syntax. Return as HTML Ordered List (<ol><li>...</li></ol>)." },
        refleksi: { type: Type.STRING, description: "Activity for 'Refleksi' phase (Closing). Return as HTML Ordered List (<ol><li>...</li></ol>)." },
      },
      required: ["memahami", "mengaplikasi", "refleksi"]
    },
    assessments: {
      type: Type.OBJECT,
      properties: {
        initial: { type: Type.STRING, description: "Diagnostic assessment ideas" },
        process: { type: Type.STRING, description: "Formative assessment (rubric, observation)" },
        final: { type: Type.STRING, description: "Summative assessment (product, portfolio)" },
      },
      required: ["initial", "process", "final"]
    }
  },
  required: ["studentCharacteristics", "crossDisciplinary", "topics", "partnerships", "environment", "digitalTools", "learningExperiences", "assessments"]
};

export const generateRPM = async (data: FormData, apiKey: string): Promise<GeneratedContent> => {
  if (!apiKey) throw new Error("API Key wajib diisi.");

  const ai = getAI(apiKey);
  const pedagogies = data.meetings.map(m => `Pertemuan ${m.meetingNumber}: ${m.pedagogy}`).join(", ");
  const dimensions = data.dimensions.join(", ");

  const prompt = `
    Bertindaklah sebagai ahli kurikulum SD Indonesia. Buatlah konten Rencana Pembelajaran Mendalam (RPM) untuk SDN Pekayon 09.

    Data Input:
    - Kelas: ${data.classLevel}
    - Mapel: ${data.subject}
    - Materi: ${data.materi}
    - CP: ${data.cp}
    - TP: ${data.tp}
    - Dimensi Profil Pelajar: ${dimensions}
    - Praktik Pedagogis per Pertemuan: ${pedagogies}

    Tugas:
    Lengkapi bagian-bagian rencana pembelajaran yang kosong berikut ini dengan bahasa Indonesia yang formal, edukatif, namun aplikatif:
    1. Karakteristik Siswa (Siswa): Deskripsikan karakteristik umum siswa kelas ${data.classLevel} SD.
    2. Lintas Disiplin Ilmu: Hubungkan materi ini dengan mata pelajaran lain.
    3. Topik Pembelajaran: Breakdown materi menjadi topik spesifik.
    4. Kemitraan: Siapa yang bisa dilibatkan?
    5. Lingkungan: Bagaimana setting kelas/luar kelas?
    6. Digital: Rekomendasi tools spesifik (misal: Quizizz, Canva, Youtube, dll).
    7. Pengalaman Belajar (PENTING: Gunakan format HTML <ol> dan <li> untuk membuat numbering ke bawah yang rapi):
       - Memahami (Awal): Kegiatan pemantik yang 'berkesadaran/bermakna/menggembirakan'. Format: <ol><li>...</li></ol>
       - Mengaplikasi (Inti): Rangkaian kegiatan inti yang SANGAT SESUAI dengan sintaks ${pedagogies}. Jika ada beda pedagogi tiap pertemuan, gabungkan narasi sintaksnya. Format: <ol><li>...</li></ol>
       - Refleksi (Penutup): Kegiatan penutup. Format: <ol><li>...</li></ol>
    8. Asesmen: Awal, Proses, dan Akhir.
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: generatedContentSchema,
      }
    });

    const result = JSON.parse(response.text || "{}");
    return result as GeneratedContent;
  } catch (error) {
    console.error("Error generating RPM:", error);
    throw error; // Re-throw to handle in UI
  }
};

const getPhase = (classLevel: string): 'FaseA' | 'FaseB' | 'FaseC' => {
  if (classLevel === ClassLevel.Kelas1 || classLevel === ClassLevel.Kelas2) return 'FaseA';
  if (classLevel === ClassLevel.Kelas3 || classLevel === ClassLevel.Kelas4) return 'FaseB';
  return 'FaseC';
};

export const getFieldSuggestions = async (
  field: 'cp' | 'tp' | 'materi',
  subject: Subject,
  classLevel: ClassLevel,
  apiKey: string,
  currentContext: string = "" 
): Promise<string[]> => {
    if (!apiKey) return ["Harap masukkan API Key terlebih dahulu."];

    const ai = getAI(apiKey);
    let fieldName = "";
    let promptContext = "";

    const phase = getPhase(classLevel);

    // Check if we have official CP reference data from the PDF
    const officialCP = CP_REF[subject]?.[phase];

    if (field === 'cp') {
        fieldName = "Capaian Pembelajaran (CP)";
        if (officialCP) {
          promptContext = `
            Berikut adalah referensi CP RESMI (Kurikulum Merdeka) untuk ${subject} Fase ${phase.replace('Fase', '')}:
            "${officialCP}"

            Tugas: Buat 5 variasi kalimat CP yang spesifik berdasarkan referensi di atas. Pecah menjadi poin-poin fokus jika referensi terlalu panjang.
          `;
        } else {
          promptContext = `Buat 5 opsi CP yang sesuai Kurikulum Merdeka untuk mapel ini.`;
        }
    } else if (field === 'tp') {
        fieldName = "Tujuan Pembelajaran (TP)";
        if (currentContext && currentContext.length > 5) {
           promptContext = `
             User telah memilih Capaian Pembelajaran (CP) berikut:
             "${currentContext}"

             Tugas: Turunkan 5 opsi Tujuan Pembelajaran (TP) yang logis, terukur, dan spesifik yang BERSUMBER LANGSUNG dari CP di atas.
           `;
        } else {
           // Fallback if no CP is selected, look at official CP if available
           if (officialCP) {
             promptContext = `
               Gunakan referensi CP Fase ${phase.replace('Fase', '')} berikut: "${officialCP}".
               Buat 5 opsi Tujuan Pembelajaran (TP) yang relevan.
             `;
           }
        }
    } else if (field === 'materi') {
        fieldName = "Materi Pelajaran";
        if (currentContext) {
           promptContext = `Berdasarkan CP/TP berikut: "${currentContext}", sarankan 5 topik materi pokok yang relevan.`;
        }
    }

    const prompt = `
      Berikan 5 opsi pilihan ${fieldName} untuk mata pelajaran ${subject} Kelas ${classLevel} SD.
      ${promptContext}
      Output wajib JSON: { "options": ["opsi 1", "opsi 2", ...] }
    `;

    try {
        const response = await ai.models.generateContent({
            model: "gemini-3-flash-preview",
            contents: prompt,
            config: {
                responseMimeType: "application/json",
                responseSchema: {
                    type: Type.OBJECT,
                    properties: {
                        options: {
                            type: Type.ARRAY,
                            items: { type: Type.STRING }
                        }
                    }
                }
            }
        });
        const result = JSON.parse(response.text || "{}");
        return result.options || [];
    } catch (e) {
        console.error(e);
        return ["Gagal mengambil saran. Periksa API Key Anda."];
    }
};

import React, { useState, useEffect } from 'react';
import { 
  ClassLevel, Semester, Subject, PedagogicalPractice, 
  GraduateDimension, FormData
} from '../types';
import { getFieldSuggestions } from '../services/geminiService';
import { Sparkles, Loader2, BookOpen, User, Calendar, CheckCircle, X, CheckSquare, Square, Key, Eye, EyeOff } from 'lucide-react';

interface InputFormProps {
  onSubmit: (data: FormData, apiKey: string) => void;
  isLoading: boolean;
}

const InputForm: React.FC<InputFormProps> = ({ onSubmit, isLoading }) => {
  const [apiKey, setApiKey] = useState('');
  const [showApiKey, setShowApiKey] = useState(false);

  const [formData, setFormData] = useState<FormData>({
    teacherName: '',
    teacherNIP: '',
    principalName: 'Veria Wulandari,S.Pd',
    principalNIP: '198102012008012028',
    classLevel: ClassLevel.Kelas1,
    semester: Semester.Ganjil,
    subject: Subject.BahasaIndonesia,
    cp: '',
    tp: '',
    materi: '',
    meetingCount: 1,
    duration: '2 x 35 menit',
    meetings: [{ meetingNumber: 1, pedagogy: PedagogicalPractice.InkuiriDiscovery }],
    dimensions: []
  });

  const [suggestions, setSuggestions] = useState<string[]>([]);
  const [activeField, setActiveField] = useState<'cp' | 'tp' | 'materi' | null>(null);
  const [loadingField, setLoadingField] = useState<'cp' | 'tp' | 'materi' | null>(null);
  const [selectedSuggestions, setSelectedSuggestions] = useState<string[]>([]);

  // Load API Key from LocalStorage on mount
  useEffect(() => {
    const savedKey = localStorage.getItem('gemini_api_key');
    if (savedKey) setApiKey(savedKey);
  }, []);

  // Update meetings array when count changes
  useEffect(() => {
    setFormData(prev => {
      const currentCount = prev.meetings.length;
      const targetCount = prev.meetingCount;

      if (currentCount === targetCount) return prev;

      let newMeetings = [...prev.meetings];
      if (targetCount > currentCount) {
        for (let i = currentCount + 1; i <= targetCount; i++) {
          newMeetings.push({ meetingNumber: i, pedagogy: PedagogicalPractice.InkuiriDiscovery });
        }
      } else {
        newMeetings = newMeetings.slice(0, targetCount);
      }
      return { ...prev, meetings: newMeetings };
    });
  }, [formData.meetingCount]);

  const handleApiKeyChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const val = e.target.value;
    setApiKey(val);
    localStorage.setItem('gemini_api_key', val);
  };

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement | HTMLTextAreaElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  const handleDimensionChange = (dim: GraduateDimension) => {
    setFormData(prev => {
      const exists = prev.dimensions.includes(dim);
      if (exists) {
        return { ...prev, dimensions: prev.dimensions.filter(d => d !== dim) };
      } else {
        return { ...prev, dimensions: [...prev.dimensions, dim] };
      }
    });
  };

  const handlePedagogyChange = (index: number, value: PedagogicalPractice) => {
    const newMeetings = [...formData.meetings];
    newMeetings[index].pedagogy = value;
    setFormData(prev => ({ ...prev, meetings: newMeetings }));
  };

  const handleGetSuggestion = async (field: 'cp' | 'tp' | 'materi') => {
    if (!apiKey) {
      alert("Mohon isi Google API Key terlebih dahulu di bagian atas form.");
      return;
    }

    setLoadingField(field);
    setSuggestions([]);
    setSelectedSuggestions([]); // Reset selections
    setActiveField(null);

    // Determine context for the suggestion
    let context = "";
    if (field === 'tp') {
        // If asking for TP, pass the current CP as context
        context = formData.cp;
    } else if (field === 'materi') {
        // If asking for Materi, pass CP + TP
        context = `CP: ${formData.cp}. TP: ${formData.tp}`;
    }

    const opts = await getFieldSuggestions(field, formData.subject, formData.classLevel, apiKey, context);

    setSuggestions(opts);
    setActiveField(field);
    setLoadingField(null);
  };

  // Handle single click selection (for CP)
  const handleSelectSuggestion = (val: string) => {
    if (activeField) {
        setFormData(prev => ({ ...prev, [activeField]: val }));
        setActiveField(null);
        setSuggestions([]);
        setSelectedSuggestions([]);
    }
  };

  // Handle toggle selection (for TP and Materi checkbox)
  const handleToggleSuggestion = (val: string) => {
    setSelectedSuggestions(prev => {
      if (prev.includes(val)) {
        return prev.filter(item => item !== val);
      } else {
        return [...prev, val];
      }
    });
  };

  // Apply multiple selected suggestions
  const handleApplySelected = () => {
    if (activeField && selectedSuggestions.length > 0) {
      // Join selected items with newline
      const joinedValue = selectedSuggestions.join('\n');
      setFormData(prev => ({ ...prev, [activeField]: joinedValue }));
      setActiveField(null);
      setSuggestions([]);
      setSelectedSuggestions([]);
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!apiKey) {
      alert("Mohon isi Google API Key terlebih dahulu.");
      return;
    }
    onSubmit(formData, apiKey);
  };

  const renderSuggestionInput = (field: 'cp' | 'tp' | 'materi', label: string, rows: number, placeholder: string) => {
    // TP and Materi use multi-select checkbox logic
    const isMultiSelect = field === 'tp' || field === 'materi';

    return (
      <div className="relative group">
          <div className="flex justify-between items-end mb-1">
               <label className="block text-sm font-semibold text-slate-700">{label}</label>
               <button 
                  type="button" 
                  onClick={() => handleGetSuggestion(field)}
                  disabled={loadingField === field}
                  className="text-xs flex items-center gap-1 bg-teal-50 hover:bg-teal-100 text-teal-700 px-2 py-1 rounded-full font-medium transition-colors"
               >
                  {loadingField === field ? <Loader2 size={12} className="animate-spin" /> : <Sparkles size={12} />}
                  {loadingField === field ? 'Mencari...' : 'Saran AI'}
               </button>
          </div>
          <textarea 
              required 
              name={field} 
              value={formData[field]} 
              onChange={handleChange} 
              rows={rows} 
              className="w-full p-2 text-sm border border-slate-300 rounded-lg focus:ring-2 focus:ring-teal-500 outline-none" 
              placeholder={placeholder} 
          />
          {activeField === field && suggestions.length > 0 && (
              <div className="absolute z-20 w-full bg-white border border-slate-200 shadow-2xl rounded-lg mt-1 max-h-60 flex flex-col animate-fade-in-up">
                   <div className="sticky top-0 bg-slate-50 border-b border-slate-100 p-2 flex justify-between items-center backdrop-blur-sm bg-opacity-90 z-10 rounded-t-lg">
                      <span className="text-xs font-bold text-teal-700">
                        {isMultiSelect ? 'Pilih satu atau lebih:' : `Pilih Saran ${label}:`}
                      </span>
                      <button type="button" onClick={() => setActiveField(null)} className="text-slate-400 hover:text-red-500 transition">
                          <X size={14} />
                      </button>
                   </div>

                   <ul className="overflow-y-auto flex-1">
                      {suggestions.map((s, idx) => {
                          const isSelected = selectedSuggestions.includes(s);
                          return (
                            <li 
                                key={idx} 
                                onClick={() => isMultiSelect ? handleToggleSuggestion(s) : handleSelectSuggestion(s)} 
                                className={`p-3 text-sm border-b border-slate-50 last:border-0 cursor-pointer transition-colors flex items-start gap-3 ${
                                  isSelected ? 'bg-teal-50 text-teal-900' : 'hover:bg-slate-50 text-slate-700'
                                }`}
                            >
                                {isMultiSelect && (
                                  <div className={`mt-0.5 ${isSelected ? 'text-teal-600' : 'text-slate-300'}`}>
                                    {isSelected ? <CheckSquare size={16} /> : <Square size={16} />}
                                  </div>
                                )}
                                <span className="flex-1">{s}</span>
                            </li>
                          );
                      })}
                   </ul>

                   {isMultiSelect && (
                     <div className="sticky bottom-0 p-2 bg-white border-t border-slate-100 rounded-b-lg">
                       <button
                         type="button"
                         onClick={handleApplySelected}
                         disabled={selectedSuggestions.length === 0}
                         className="w-full py-2 bg-teal-600 hover:bg-teal-700 disabled:bg-slate-300 text-white text-sm font-semibold rounded-lg transition-colors"
                       >
                         Gunakan {selectedSuggestions.length > 0 ? `(${selectedSuggestions.length})` : ''} {field === 'tp' ? 'Tujuan Pembelajaran' : 'Materi'}
                       </button>
                     </div>
                   )}
              </div>
          )}
      </div>
    );
  };

  return (
    <form onSubmit={handleSubmit} className="bg-white p-6 md:p-8 rounded-2xl shadow-xl border border-slate-100 max-w-4xl mx-auto space-y-8">

      {/* Header Section */}
      <div className="text-center border-b border-slate-100 pb-6">
        <h2 className="text-2xl font-bold text-teal-700 font-comic">Formulir RPM</h2>
        <p className="text-slate-500 text-sm mt-1">Isi data di bawah ini untuk men-generate rencana pembelajaran.</p>
      </div>

      {/* API Key Configuration */}
      <div className="bg-yellow-50 border border-yellow-200 rounded-xl p-4">
        <div className="flex items-start gap-3">
          <Key className="text-yellow-600 mt-1 shrink-0" size={20} />
          <div className="w-full">
             <label className="block text-sm font-bold text-yellow-800 mb-1">
               Google Gemini API Key (Wajib)
             </label>
             <p className="text-xs text-yellow-700 mb-2">
               Untuk menggunakan generator ini secara GRATIS, Anda memerlukan API Key sendiri. 
               <a href="https://aistudio.google.com/app/apikey" target="_blank" rel="noreferrer" className="underline font-bold ml-1 hover:text-yellow-900">
                 Dapatkan Key di sini
               </a>
             </p>
             <div className="relative">
               <input 
                 type={showApiKey ? "text" : "password"} 
                 value={apiKey} 
                 onChange={handleApiKeyChange}
                 placeholder="Paste API Key Anda di sini (AIzaSy...)" 
                 className="w-full p-2 pr-10 border border-yellow-300 rounded-lg focus:ring-2 focus:ring-yellow-500 outline-none text-sm bg-white"
               />
               <button 
                 type="button"
                 onClick={() => setShowApiKey(!showApiKey)}
