import React, { useState } from 'react';
import InputForm from './components/InputForm';
import RPMPreview from './components/RPMPreview';
import { FormData, RPMResult } from './types';
import { generateRPM } from './services/geminiService';
import { Heart } from 'lucide-react';

const App: React.FC = () => {
  const [rpmResult, setRpmResult] = useState<RPMResult | null>(null);
  const [isLoading, setIsLoading] = useState(false);

  const handleSubmit = async (data: FormData, apiKey: string) => {
    setIsLoading(true);
    try {
      const generatedContent = await generateRPM(data, apiKey);
      const fullResult: RPMResult = {
        ...data,
        ...generatedContent
      };
      setRpmResult(fullResult);
    } catch (error) {
      alert("Terjadi kesalahan saat menghubungi AI. Pastikan API Key Anda benar atau kuota Anda masih tersedia.");
      console.error(error);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="min-h-screen bg-slate-50 font-sans text-slate-900">

      {/* Header / Navbar */}
      <header className="bg-gradient-to-r from-red-900 to-rose-900 text-white shadow-lg sticky top-0 z-40">
        <div className="max-w-7xl mx-auto px-4 py-4 flex items-center justify-between">
          <div className="flex items-center gap-3">
             <div className="bg-white p-1 rounded-lg backdrop-blur-sm shadow-sm">
               <img 
                 src="https://i.ibb.co.com/1fQ81J6v/LOGO-PEKAYON-09.jpg" 
                 alt="Logo SDN Pekayon 09" 
                 className="w-10 h-10 object-contain" 
               />
             </div>
             <div>
               <h1 className="text-xl md:text-2xl font-bold font-comic tracking-tight">Generator RPM</h1>
               <p className="text-xs text-red-100 opacity-90">SDN Pekayon 09</p>
             </div>
          </div>
          <div className="hidden md:block text-xs text-red-100 text-right opacity-80">
            <p>Perencanaan Pembelajaran Mendalam</p>
            <p>Powered by Gemini AI</p>
          </div>
        </div>
      </header>

      {/* Main Content */}
      <main className="p-4 md:p-8">
        {!rpmResult ? (
          <div className="animate-fade-in-up">
             <div className="max-w-4xl mx-auto mb-8 text-center space-y-2">
                <h2 className="text-3xl font-bold text-slate-800">Selamat Datang, Bapak/Ibu Guru! 👋</h2>
                <p className="text-slate-600">Mari buat rencana pembelajaran yang bermakna dan terstruktur hanya dalam hitungan detik.</p>
             </div>
             <InputForm onSubmit={handleSubmit} isLoading={isLoading} />
          </div>
        ) : (
          <div className="animate-fade-in">
            <RPMPreview data={rpmResult} onReset={() => setRpmResult(null)} />
          </div>
        )}
      </main>

      {/* Footer */}
      <footer className="bg-white border-t border-slate-200 mt-12 py-8 no-print">
        <div className="max-w-7xl mx-auto px-4 text-center">
          <p className="flex items-center justify-center gap-2 text-slate-500 text-sm">
            Dibuat dengan <Heart size={16} className="text-red-500 fill-red-500" /> untuk Pendidikan Indonesia
          </p>
          <p className="text-slate-400 text-xs mt-2">
             © {new Date().getFullYear()} SDN Pekayon 09. All rights reserved. <br/>
             <span className="font-medium text-slate-500">Created by Teguh Firmansyah @goehfirmaan</span>
          </p>
        </div>
      </footer>
    </div>
  );
};

