const ai = new GoogleGenAI({ apiKey: API_KEY });

// Helper untuk membersihkan string JSON dari markdown formatting (```json ... ```)
// dan teks percakapan tambahan
const cleanJsonString = (text: string | undefined): string => {
  if (!text) return "{}";

  // 1. Hapus markdown code blocks
  let clean = text.replace(/```json/g, "").replace(/```/g, "").trim();

  // 2. Ambil hanya bagian JSON (antara kurung kurawal terluar)
  // Ini menangani kasus jika AI menjawab: "Tentu, ini JSON nya: { ... }"
  const firstBrace = clean.indexOf('{');
  const lastBrace = clean.lastIndexOf('}');

  if (firstBrace !== -1 && lastBrace !== -1) {
    clean = clean.substring(firstBrace, lastBrace + 1);
  }

  return clean;
};

const generatedContentSchema: Schema = {
  type: Type.OBJECT,
  properties: {
    studentCharacteristics: { type: Type.STRING, description: "Description of student characteristics based on age/class" },
    crossDisciplinary: { type: Type.STRING, description: "Connection to other subjects" },
    topics: { type: Type.STRING, description: "Specific learning topics derived from material" },
    partnerships: { type: Type.STRING, description: "Learning partnerships (parents, experts, community)" },
    environment: { type: Type.STRING, description: "Learning environment setup" },
