               >
                  {loadingField === field ? <Loader2 size={10} className="animate-spin" /> : <Sparkles size={10} />}
                  {loadingField === field ? 'Thinking...' : 'AI Suggestion'}
               </button>
          </div>
          <div className="relative">
            <textarea 
