            <InputLabel label="Semester" />
            <div className="relative">
              <select name="semester" value={formData.semester} onChange={handleChange} className={SelectClasses}>
                {Object.values(Semester).map(s => <option key={s} value={s}>{s}</option>)}
              </select>
              <ChevronDown className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-400 pointer-events-none" size={16} />
            </div>
          </div>
          <div className="relative">
            <InputLabel label="Mata Pelajaran" />
            <div className="relative">
              <select name="subject" value={formData.subject} onChange={handleChange} className={SelectClasses}>
                {Object.values(Subject).map(s => <option key={s} value={s}>{s}</option>)}
              </select>
              <ChevronDown className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-400 pointer-events-none" size={16} />
            </div>
          </div>
        </div>

        {/* Suggestion Inputs */}
        <div className="space-y-6">
             {renderSuggestionInput('cp', 'Capaian Pembelajaran (CP)', 3, 'Tulis CP atau gunakan AI...')}
             {renderSuggestionInput('tp', 'Tujuan Pembelajaran (TP)', 2, 'Tulis TP atau gunakan AI...')}
             {renderSuggestionInput('materi', 'Materi Pelajaran', 2, 'Tulis Materi atau gunakan AI...')}
        </div>
      </section>

      {/* Detil Pertemuan */}
      <section>
        <SectionTitle title="Strategi Pertemuan" />
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6 mb-6">
           <div className="relative">
            <InputLabel label="Jumlah Pertemuan" />
            <div className="relative">
              <select name="meetingCount" value={formData.meetingCount} onChange={(e) => setFormData({...formData, meetingCount: parseInt(e.target.value)})} className={SelectClasses}>
                {[1, 2, 3, 4, 5, 6, 7, 8].map(n => <option key={n} value={n}>{n} Pertemuan</option>)}
              </select>
              <ChevronDown className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-400 pointer-events-none" size={16} />
            </div>
           </div>
           <div>
            <InputLabel label="Durasi Total" />
            <input name="duration" value={formData.duration} onChange={handleChange} className={InputClasses} placeholder="Contoh: 2 x 35 menit" />
           </div>
        </div>

        <div className="space-y-3">
           <InputLabel label="Model Pembelajaran per Pertemuan" />
           {formData.meetings.map((meeting, idx) => (
             <div key={idx} className="flex items-center gap-4 p-3 rounded-lg border border-slate-100 bg-slate-50/50 hover:border-slate-300 transition-colors">
                <span className="text-xs font-bold text-slate-400 uppercase tracking-wider w-28">Pertemuan {meeting.meetingNumber}</span>
                <div className="relative flex-1">
                  <select 
                    value={meeting.pedagogy} 
                    onChange={(e) => handlePedagogyChange(idx, e.target.value as PedagogicalPractice)}
                    className="w-full bg-transparent text-sm text-slate-700 outline-none cursor-pointer appearance-none font-medium"
                  >
                    {Object.values(PedagogicalPractice).map(p => <option key={p} value={p}>{p}</option>)}
                  </select>
                  <ChevronDown className="absolute right-0 top-1/2 -translate-y-1/2 text-slate-400 pointer-events-none" size={14} />
                </div>
             </div>
           ))}
        </div>
      </section>

      {/* Dimensi Lulusan */}
      <section>
        <SectionTitle title="Profil Pelajar Pancasila" />
        <div className="grid grid-cols-2 md:grid-cols-4 gap-3">
           {Object.values(GraduateDimension).map((dim) => (
             <label key={dim} className={`group flex flex-col items-start gap-2 p-4 rounded-xl border cursor-pointer transition-all duration-300 ${
               formData.dimensions.includes(dim) 
                ? 'bg-slate-800 border-slate-800 text-white shadow-lg' 
                : 'bg-white border-slate-200 text-slate-500 hover:border-slate-300'
             }`}>
                <div className="flex justify-between w-full">
                  <span className={`text-[10px] font-bold uppercase tracking-wider ${formData.dimensions.includes(dim) ? 'text-slate-300' : 'text-slate-300'}`}>Dimensi</span>
                  <input type="checkbox" checked={formData.dimensions.includes(dim)} onChange={() => handleDimensionChange(dim)} className="hidden" />
                  {formData.dimensions.includes(dim) && <Check size={14} className="text-teal-400" />}
                </div>
                <span className="text-sm font-semibold leading-tight">{dim}</span>
             </label>
           ))}
        </div>
      </section>

      {/* Submit Button */}
      <div className="pt-8">
        <button 
          type="submit" 
          disabled={isLoading}
          className="w-full bg-slate-900 text-white font-medium py-4 rounded-xl shadow-lg hover:shadow-xl hover:-translate-y-1 disabled:opacity-70 disabled:cursor-not-allowed disabled:transform-none flex justify-center items-center gap-3 transition-all duration-300"
        >
          {isLoading ? (
            <>
              <Loader2 className="animate-spin text-slate-400" size={20} />
              <span className="text-slate-200">Sedang Memproses...</span>
            </>
          ) : (
            <>
              <span>Generate Rencana Pembelajaran</span>
              <Sparkles className="text-teal-400" size={18} />
            </>
          )}
        </button>
      </div>
    </form>
  );
};

export default InputForm;

import React, { useState } from 'react';
