               <h1 className="text-xl font-serif-display font-bold text-slate-900 leading-none">RPM Generator</h1>
               <p className="text-[10px] uppercase tracking-[0.2em] text-slate-500 font-bold mt-1">SDN Pekayon 09</p>
             </div>
          </div>
          <div className="hidden md:block">
            <span className="px-3 py-1.5 bg-slate-100 text-slate-600 text-xs font-bold tracking-wide border border-slate-200">
