export default App;

import React, { useState, useEffect } from 'react';
import { 
  ClassLevel, Semester, Subject, PedagogicalPractice, 
  GraduateDimension, FormData
} from '../types';
import { getFieldSuggestions } from '../services/geminiService';
import { Loader2, Check, X, ChevronDown, Sparkles, Eye, EyeOff } from 'lucide-react';

interface InputFormProps {
  onSubmit: (data: FormData, apiKey: string) => void;
  isLoading: boolean;
}

const InputForm: React.FC<InputFormProps> = ({ onSubmit, isLoading }) => {
  const [apiKey, setApiKey] = useState('');
  const [showApiKey, setShowApiKey] = useState(false);

  const [formData, setFormData] = useState<FormData>({
    teacherName: '',
    teacherNIP: '',
    principalName: 'Veria Wulandari,S.Pd',
    principalNIP: '198102012008012028',
    classLevel: ClassLevel.Kelas1,
    semester: Semester.Ganjil,
    subject: Subject.BahasaIndonesia,
    cp: '',
    tp: '',
    materi: '',
    meetingCount: 1,
    duration: '2 x 35 menit',
    meetings: [{ meetingNumber: 1, pedagogy: PedagogicalPractice.InkuiriDiscovery }],
    dimensions: []
  });

  const [suggestions, setSuggestions] = useState<string[]>([]);
  const [activeField, setActiveField] = useState<'cp' | 'tp' | 'materi' | null>(null);
  const [loadingField, setLoadingField] = useState<'cp' | 'tp' | 'materi' | null>(null);
  const [selectedSuggestions, setSelectedSuggestions] = useState<string[]>([]);

  // Load API Key from LocalStorage on mount
  useEffect(() => {
    const savedKey = localStorage.getItem('gemini_api_key');
    if (savedKey) setApiKey(savedKey);
  }, []);

  // Update meetings array when count changes
  useEffect(() => {
    setFormData(prev => {
      const currentCount = prev.meetings.length;
      const targetCount = prev.meetingCount;

      if (currentCount === targetCount) return prev;

      let newMeetings = [...prev.meetings];
      if (targetCount > currentCount) {
        for (let i = currentCount + 1; i <= targetCount; i++) {
          newMeetings.push({ meetingNumber: i, pedagogy: PedagogicalPractice.InkuiriDiscovery });
        }
      } else {
        newMeetings = newMeetings.slice(0, targetCount);
      }
      return { ...prev, meetings: newMeetings };
    });
  }, [formData.meetingCount]);

  const handleApiKeyChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const val = e.target.value;
    setApiKey(val);
    localStorage.setItem('gemini_api_key', val);
  };

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement | HTMLTextAreaElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  const handleDimensionChange = (dim: GraduateDimension) => {
    setFormData(prev => {
      const exists = prev.dimensions.includes(dim);
      if (exists) {
        return { ...prev, dimensions: prev.dimensions.filter(d => d !== dim) };
      } else {
        return { ...prev, dimensions: [...prev.dimensions, dim] };
      }
    });
  };

  const handlePedagogyChange = (index: number, value: PedagogicalPractice) => {
    const newMeetings = [...formData.meetings];
    newMeetings[index].pedagogy = value;
    setFormData(prev => ({ ...prev, meetings: newMeetings }));
  };

  const handleGetSuggestion = async (field: 'cp' | 'tp' | 'materi') => {
    if (!apiKey) {
      alert("Mohon isi Google API Key terlebih dahulu di bagian atas form.");
      return;
    }

    setLoadingField(field);
    setSuggestions([]);
    setSelectedSuggestions([]); // Reset selections
    setActiveField(null);

    // Determine context for the suggestion
    let context = "";
    if (field === 'tp') {
        context = formData.cp;
    } else if (field === 'materi') {
        context = `CP: ${formData.cp}. TP: ${formData.tp}`;
    }

    const opts = await getFieldSuggestions(field, formData.subject, formData.classLevel, apiKey, context);

    setSuggestions(opts);
    setActiveField(field);
    setLoadingField(null);
  };

  const handleSelectSuggestion = (val: string) => {
    if (activeField) {
        setFormData(prev => ({ ...prev, [activeField]: val }));
        setActiveField(null);
        setSuggestions([]);
        setSelectedSuggestions([]);
    }
  };

  const handleToggleSuggestion = (val: string) => {
    setSelectedSuggestions(prev => {
      if (prev.includes(val)) {
        return prev.filter(item => item !== val);
      } else {
        return [...prev, val];
      }
    });
  };

  const handleApplySelected = () => {
    if (activeField && selectedSuggestions.length > 0) {
      const joinedValue = selectedSuggestions.join('\n');
      setFormData(prev => ({ ...prev, [activeField]: joinedValue }));
      setActiveField(null);
      setSuggestions([]);
      setSelectedSuggestions([]);
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!apiKey) {
      alert("Mohon isi Google API Key terlebih dahulu.");
      return;
    }
    onSubmit(formData, apiKey);
  };

  // --- Styles Constants ---
  const SectionTitle = ({ title }: { title: string }) => (
    <div className="mb-6 mt-4">
      <h3 className="text-xs font-bold uppercase tracking-[0.15em] text-slate-800 mb-2">{title}</h3>
      <div className="h-px w-full bg-slate-200"></div>
    </div>
  );

  const InputLabel = ({ label, required }: { label: string, required?: boolean }) => (
    <label className="block text-sm font-bold text-slate-700 mb-2 tracking-wide">
      {label} {required && <span className="text-red-500">*</span>}
    </label>
  );

  const InputClasses = "w-full px-4 py-3 bg-white border border-slate-300 rounded-lg text-sm font-medium text-slate-900 focus:ring-1 focus:ring-slate-900 focus:border-slate-900 outline-none transition-all duration-200 placeholder:text-slate-400";
  const SelectClasses = "w-full px-4 py-3 bg-white border border-slate-300 rounded-lg text-sm font-medium text-slate-900 focus:ring-1 focus:ring-slate-900 focus:border-slate-900 outline-none appearance-none cursor-pointer transition-all duration-200";

  const renderSuggestionInput = (field: 'cp' | 'tp' | 'materi', label: string, rows: number, placeholder: string) => {
    const isMultiSelect = field === 'tp' || field === 'materi';

    return (
      <div className="relative group space-y-2">
          <div className="flex justify-between items-center">
               <InputLabel label={label} required />
               <button 
                  type="button" 
                  onClick={() => handleGetSuggestion(field)}
                  disabled={loadingField === field}
                  className="px-3 py-1 bg-slate-100 hover:bg-slate-200 text-slate-700 rounded text-xs font-bold tracking-wide uppercase transition-colors flex items-center gap-1.5 border border-slate-200"
               >
                  {loadingField === field ? <Loader2 size={12} className="animate-spin" /> : <Sparkles size={12} />}
                  {loadingField === field ? 'Thinking...' : 'AI Suggestion'}
               </button>
          </div>
          <div className="relative">
            <textarea 
                required 
                name={field} 
                value={formData[field]} 
                onChange={handleChange} 
                rows={rows} 
                className={`${InputClasses} resize-none leading-relaxed`}
                placeholder={placeholder} 
            />
          </div>

          {/* Dropdown Suggestions */}
          {activeField === field && suggestions.length > 0 && (
              <div className="absolute z-30 w-full bg-white border border-slate-200 shadow-xl rounded-lg mt-2 overflow-hidden animate-fade-in-up ring-1 ring-slate-100">
                   <div className="px-4 py-3 bg-slate-50 border-b border-slate-200 flex justify-between items-center">
                      <span className="text-xs font-bold text-slate-700 uppercase tracking-widest">
                        {isMultiSelect ? 'Pilih Opsi (Multi)' : 'Pilih Saran'}
                      </span>
                      <button type="button" onClick={() => setActiveField(null)} className="text-slate-400 hover:text-red-500 transition">
                          <X size={16} />
                      </button>
                   </div>

                   <ul className="max-h-72 overflow-y-auto">
                      {suggestions.map((s, idx) => {
                          const isSelected = selectedSuggestions.includes(s);
                          return (
                            <li 
                                key={idx} 
                                onClick={() => isMultiSelect ? handleToggleSuggestion(s) : handleSelectSuggestion(s)} 
                                className={`px-5 py-4 text-sm border-b border-slate-100 last:border-0 cursor-pointer transition-colors flex items-start gap-4 leading-relaxed ${
                                  isSelected ? 'bg-slate-100 text-slate-900 font-medium' : 'hover:bg-slate-50 text-slate-600'
                                }`}
                            >
                                {isMultiSelect && (
                                  <div className={`mt-0.5 w-5 h-5 rounded border flex items-center justify-center shrink-0 transition-all ${isSelected ? 'bg-slate-900 border-slate-900 text-white' : 'border-slate-300 bg-white'}`}>
                                    {isSelected && <Check size={12} strokeWidth={3} />}
                                  </div>
                                )}
                                <span className="flex-1">{s}</span>
                            </li>
                          );
                      })}
                   </ul>

                   {isMultiSelect && (
                     <div className="p-4 bg-slate-50 border-t border-slate-200">
                       <button
                         type="button"
                         onClick={handleApplySelected}
                         disabled={selectedSuggestions.length === 0}
                         className="w-full py-3 bg-slate-900 hover:bg-slate-800 disabled:bg-slate-300 text-white text-xs font-bold uppercase tracking-widest rounded-lg transition-all"
                       >
                         Gunakan {selectedSuggestions.length} Pilihan
                       </button>
                     </div>
                   )}
              </div>
          )}
      </div>
    );
  };

  return (
    <form onSubmit={handleSubmit} className="bg-white rounded-xl border border-slate-200 p-8 md:p-12 max-w-4xl mx-auto space-y-12 animate-fade-in-up delay-100 shadow-sm">

      {/* API Key Configuration - High Contrast Box */}
      <div className="bg-slate-900 text-slate-200 rounded-lg p-6">
        <div className="flex flex-col md:flex-row md:items-center gap-6">
          <div className="flex-1">
             <label className="text-xs font-bold text-slate-400 uppercase tracking-widest mb-2 block">
               Konfigurasi: Gemini API Key
             </label>
             <div className="relative">
               <input 
                 type={showApiKey ? "text" : "password"} 
                 value={apiKey} 
                 onChange={handleApiKeyChange}
                 placeholder="Tempel API Key di sini..." 
                 className="w-full bg-slate-800 border-2 border-slate-700 focus:border-white rounded-md px-3 py-2 text-sm font-mono text-white placeholder:text-slate-600 outline-none transition-colors"
               />
             </div>
          </div>
          <div className="flex items-center gap-4 shrink-0">
             <button 
                 type="button"
                 onClick={() => setShowApiKey(!showApiKey)}
                 className="text-slate-400 hover:text-white transition-colors"
                 title={showApiKey ? "Sembunyikan" : "Tampilkan"}
               >
                 {showApiKey ? <EyeOff size={20} /> : <Eye size={20} />}
             </button>
             <div className="h-8 w-px bg-slate-700"></div>
             <a 
              href="https://aistudio.google.com/app/apikey" 
              target="_blank" 
              rel="noreferrer" 
              className="px-4 py-2 bg-white text-slate-900 text-xs font-bold rounded hover:bg-slate-200 transition-colors uppercase tracking-wide"
             >
               Buat Key
             </a>
          </div>
        </div>
      </div>

      {/* Identitas Guru & Sekolah */}
      <section>
        <SectionTitle title="1. Informasi Pendidik" />
        <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
          <div className="opacity-60 pointer-events-none grayscale">
            <InputLabel label="Nama Satuan Pendidikan" />
            <input type="text" value="SDN Pekayon 09" disabled className={InputClasses} />
          </div>
          <div className="hidden md:block"></div>

          <div>
            <InputLabel label="Nama Guru" required />
            <input required name="teacherName" value={formData.teacherName} onChange={handleChange} className={InputClasses} placeholder="Nama Lengkap & Gelar" />
          </div>
          <div>
            <InputLabel label="NIP Guru" required />
            <input required name="teacherNIP" value={formData.teacherNIP} onChange={handleChange} className={InputClasses} placeholder="NIP tanpa spasi" />
          </div>

          <div>
            <InputLabel label="Nama Kepala Sekolah" />
            <input name="principalName" value={formData.principalName} onChange={handleChange} className={InputClasses} />
          </div>
          <div>
            <InputLabel label="NIP Kepala Sekolah" />
            <input name="principalNIP" value={formData.principalNIP} onChange={handleChange} className={InputClasses} />
          </div>
        </div>
      </section>

      {/* Informasi Pembelajaran */}
      <section>
        <SectionTitle title="2. Kurikulum & Materi" />
        <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-8">
          <div className="relative">
            <InputLabel label="Kelas" />
            <div className="relative">
              <select name="classLevel" value={formData.classLevel} onChange={handleChange} className={SelectClasses}>
                {Object.values(ClassLevel).map(c => <option key={c} value={c}>Kelas {c}</option>)}
              </select>
              <ChevronDown className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-500 pointer-events-none" size={16} />
            </div>
          </div>
          <div className="relative">
            <InputLabel label="Semester" />
            <div className="relative">
              <select name="semester" value={formData.semester} onChange={handleChange} className={SelectClasses}>
                {Object.values(Semester).map(s => <option key={s} value={s}>{s}</option>)}
              </select>
              <ChevronDown className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-500 pointer-events-none" size={16} />
            </div>
          </div>
          <div className="relative">
            <InputLabel label="Mata Pelajaran" />
            <div className="relative">
              <select name="subject" value={formData.subject} onChange={handleChange} className={SelectClasses}>
                {Object.values(Subject).map(s => <option key={s} value={s}>{s}</option>)}
              </select>
              <ChevronDown className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-500 pointer-events-none" size={16} />
            </div>
          </div>
        </div>

        {/* Suggestion Inputs */}
        <div className="space-y-8">
             {renderSuggestionInput('cp', 'Capaian Pembelajaran (CP)', 3, 'Tulis CP atau gunakan tombol AI...')}
             {renderSuggestionInput('tp', 'Tujuan Pembelajaran (TP)', 2, 'Tulis TP atau gunakan tombol AI...')}
             {renderSuggestionInput('materi', 'Materi Pelajaran', 2, 'Tulis Materi atau gunakan tombol AI...')}
        </div>
      </section>

      {/* Detil Pertemuan */}
      <section>
        <SectionTitle title="3. Strategi Pertemuan" />
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6 mb-8">
           <div className="relative">
            <InputLabel label="Jumlah Pertemuan" />
            <div className="relative">
              <select name="meetingCount" value={formData.meetingCount} onChange={(e) => setFormData({...formData, meetingCount: parseInt(e.target.value)})} className={SelectClasses}>
                {[1, 2, 3, 4, 5, 6, 7, 8].map(n => <option key={n} value={n}>{n} Pertemuan</option>)}
