        <button onClick={onReset} className="flex items-center gap-2 text-slate-300 hover:text-white font-bold transition uppercase text-xs tracking-wider">
          <ArrowLeft size={16} /> Edit Data
        </button>
        <div className="flex gap-3">
          <button onClick={handleCopyToDocs} className="flex items-center gap-2 bg-transparent border border-slate-600 hover:bg-slate-800 hover:border-white px-4 py-2 rounded-lg font-bold text-xs uppercase tracking-wide transition text-white">
            <Copy size={16} />
            <span className="hidden sm:inline">Salin & Buka G-Docs</span>
          </button>
          <button onClick={handleDownloadPDF} className="flex items-center gap-2 bg-white text-slate-900 hover:bg-slate-200 px-4 py-2 rounded-lg font-bold text-xs uppercase tracking-wide transition">
            <Download size={16} />
            <span className="hidden sm:inline">Download PDF</span>
