  const InputClasses = "w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl text-sm font-medium text-slate-900 focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 focus:bg-white outline-none transition-all duration-200 placeholder:text-slate-400 hover:border-indigo-200";
  const SelectClasses = "w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl text-sm font-medium text-slate-900 focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 focus:bg-white outline-none appearance-none cursor-pointer transition-all duration-200 hover:border-indigo-200";

  const renderSuggestionInput = (field: 'cp' | 'tp' | 'materi', label: string, rows: number, placeholder: string) => {
    const isMultiSelect = field === 'tp' || field === 'materi';

    return (
      <div className="relative group space-y-2 p-5 bg-white border border-slate-100 rounded-2xl shadow-sm hover:shadow-md transition-shadow">
          <div className="flex justify-between items-center mb-1">
