          </div>

          {/* Dropdown Suggestions */}
          {activeField === field && suggestions.length > 0 && (
              <div className="absolute z-30 left-0 right-0 w-full bg-white border border-indigo-100 shadow-2xl rounded-xl mt-2 overflow-hidden animate-fade-in-up ring-4 ring-indigo-500/10">
                   <div className="px-4 py-3 bg-indigo-50/50 border-b border-indigo-100 flex justify-between items-center">
                      <span className="text-xs font-bold text-indigo-700 uppercase tracking-widest flex items-center gap-2">
                        <Sparkles size={12} />
                        {isMultiSelect ? 'Pilih Opsi (Bisa Banyak)' : 'Pilih Salah Satu'}
                      </span>
                      <button type="button" onClick={() => setActiveField(null)} className="text-slate-400 hover:text-red-500 transition">
                          <X size={16} />
                      </button>
                   </div>

                   <ul className="max-h-72 overflow-y-auto custom-scrollbar">
                      {suggestions.map((s, idx) => {
                          const isSelected = selectedSuggestions.includes(s);
                          return (
                            <li 
