                       >
                         Gunakan {selectedSuggestions.length} Pilihan
                       </button>
                     </div>
                   )}
              </div>
          )}
      </div>
    );
  };

  return (
    <form onSubmit={handleSubmit} className="bg-white rounded-3xl border border-white/50 p-8 md:p-12 max-w-4xl mx-auto space-y-8 animate-fade-in-up delay-100 shadow-xl shadow-indigo-100/50">

