        <div className="flex gap-3">
          <button onClick={handleCopyToDocs} className="flex items-center gap-2 bg-indigo-50 border border-indigo-100 hover:bg-indigo-100 px-4 py-2 rounded-lg font-bold text-xs uppercase tracking-wide transition text-indigo-700">
