  // Load API Key from LocalStorage on mount
  useEffect(() => {
    const savedKey = localStorage.getItem('gemini_api_key');
    if (savedKey) setApiKey(savedKey);
  }, []);

  // Update meetings array when count changes
  useEffect(() => {
    setFormData(prev => {
      const currentCount = prev.meetings.length;
      const targetCount = prev.meetingCount;

      if (currentCount === targetCount) return prev;

      let newMeetings = [...prev.meetings];
      if (targetCount > currentCount) {
        for (let i = currentCount + 1; i <= targetCount; i++) {
          newMeetings.push({ meetingNumber: i, pedagogy: PedagogicalPractice.InkuiriDiscovery });
        }
      } else {
        newMeetings = newMeetings.slice(0, targetCount);
      }
      return { ...prev, meetings: newMeetings };
    });
  }, [formData.meetingCount]);

  const handleApiKeyChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const val = e.target.value;
    setApiKey(val);
    localStorage.setItem('gemini_api_key', val);
  };

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement | HTMLTextAreaElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  const handleDimensionChange = (dim: GraduateDimension) => {
    setFormData(prev => {
      const exists = prev.dimensions.includes(dim);
      if (exists) {
        return { ...prev, dimensions: prev.dimensions.filter(d => d !== dim) };
      } else {
        return { ...prev, dimensions: [...prev.dimensions, dim] };
      }
    });
  };

  const handlePedagogyChange = (index: number, value: PedagogicalPractice) => {
    const newMeetings = [...formData.meetings];
    newMeetings[index].pedagogy = value;
    setFormData(prev => ({ ...prev, meetings: newMeetings }));
  };

  const handleGetSuggestion = async (field: 'cp' | 'tp' | 'materi') => {
    if (!apiKey) {
      alert("Mohon isi Google API Key terlebih dahulu di bagian atas form.");
      return;
    }

    setLoadingField(field);
    setSuggestions([]);
    setSelectedSuggestions([]); // Reset selections
    setActiveField(null);

    // Determine context for the suggestion
    let context = "";
    if (field === 'tp') {
        context = formData.cp;
    } else if (field === 'materi') {
        context = `CP: ${formData.cp}. TP: ${formData.tp}`;
    }

    const opts = await getFieldSuggestions(field, formData.subject, formData.classLevel, apiKey, context);

    setSuggestions(opts);
    setActiveField(field);
    setLoadingField(null);
  };

  const handleSelectSuggestion = (val: string) => {
    if (activeField) {
        setFormData(prev => ({ ...prev, [activeField]: val }));
        setActiveField(null);
        setSuggestions([]);
        setSelectedSuggestions([]);
    }
  };

  const handleToggleSuggestion = (val: string) => {
    setSelectedSuggestions(prev => {
      if (prev.includes(val)) {
        return prev.filter(item => item !== val);
      } else {
        return [...prev, val];
      }
    });
  };

  const handleApplySelected = () => {
    if (activeField && selectedSuggestions.length > 0) {
      const joinedValue = selectedSuggestions.join('\n');
      setFormData(prev => ({ ...prev, [activeField]: joinedValue }));
      setActiveField(null);
      setSuggestions([]);
      setSelectedSuggestions([]);
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!apiKey) {
      alert("Mohon isi Google API Key terlebih dahulu.");
      return;
    }
    onSubmit(formData, apiKey);
  };

  // --- Styles Constants ---
  const SectionTitle = ({ title, icon: Icon }: { title: string, icon: any }) => (
    <div className="mb-8 mt-10 pb-4 border-b border-slate-200">
      <div className="flex items-center gap-3 mb-1">
        <Icon size={18} className="text-slate-400" />
        <h3 className="text-xl font-serif-display font-bold text-slate-900">{title}</h3>
      </div>
    </div>
  );

  const InputLabel = ({ label, required }: { label: string, required?: boolean }) => (
    <label className="block text-xs font-bold text-slate-500 mb-2 uppercase tracking-wider">
      {label} {required && <span className="text-red-400">*</span>}
    </label>
  );

  const InputClasses = "w-full px-4 py-3 bg-white border border-slate-300 rounded-sm text-sm font-medium text-slate-900 focus:ring-1 focus:ring-slate-900 focus:border-slate-900 outline-none transition-all duration-200 placeholder:text-slate-300 hover:border-slate-400";
  const SelectClasses = "w-full px-4 py-3 bg-white border border-slate-300 rounded-sm text-sm font-medium text-slate-900 focus:ring-1 focus:ring-slate-900 focus:border-slate-900 outline-none appearance-none cursor-pointer transition-all duration-200 hover:border-slate-400";

  const renderSuggestionInput = (field: 'cp' | 'tp' | 'materi', label: string, rows: number, placeholder: string) => {
    const isMultiSelect = field === 'tp' || field === 'materi';

    return (
      <div className="relative group space-y-2 p-6 bg-slate-50 border border-slate-200 rounded-sm transition-shadow">
          <div className="flex justify-between items-center mb-1">
               <InputLabel label={label} required />
               <button 
                  type="button" 
                  onClick={() => handleGetSuggestion(field)}
                  disabled={loadingField === field}
                  className="px-3 py-1 bg-white hover:bg-slate-100 text-slate-800 rounded-sm text-xs font-medium tracking-wide transition-all flex items-center gap-1.5 border border-slate-300 shadow-sm"
               >
                  {loadingField === field ? <Loader2 size={12} className="animate-spin" /> : <Sparkles size={12} className="text-slate-400" />}
                  {loadingField === field ? 'Thinking...' : 'AI Suggestion'}
               </button>
          </div>
          <div className="relative">
            <textarea 
                required 
                name={field} 
                value={formData[field]} 
                onChange={handleChange} 
                rows={rows} 
                className={`${InputClasses} resize-none leading-relaxed border-slate-300`}
                placeholder={placeholder} 
            />
          </div>

          {/* Dropdown Suggestions */}
          {activeField === field && suggestions.length > 0 && (
              <div className="absolute z-30 left-0 right-0 w-full bg-white border border-slate-200 shadow-xl rounded-sm mt-2 overflow-hidden animate-fade-in-up">
                   <div className="px-4 py-3 bg-slate-100 border-b border-slate-200 flex justify-between items-center">
                      <span className="text-xs font-bold text-slate-600 uppercase tracking-widest flex items-center gap-2">
                        <Sparkles size={12} />
                        {isMultiSelect ? 'Pilih Opsi (Bisa Banyak)' : 'Pilih Salah Satu'}
                      </span>
                      <button type="button" onClick={() => setActiveField(null)} className="text-slate-400 hover:text-red-500 transition">
                          <X size={16} />
                      </button>
                   </div>

                   <ul className="max-h-72 overflow-y-auto custom-scrollbar">
                      {suggestions.map((s, idx) => {
                          const isSelected = selectedSuggestions.includes(s);
                          return (
                            <li 
                                key={idx} 
                                onClick={() => isMultiSelect ? handleToggleSuggestion(s) : handleSelectSuggestion(s)} 
                                className={`px-5 py-4 text-sm border-b border-slate-50 last:border-0 cursor-pointer transition-all flex items-start gap-4 leading-relaxed font-serif ${
                                  isSelected ? 'bg-slate-100 text-slate-900 font-medium' : 'hover:bg-slate-50 text-slate-600'
                                }`}
                            >
                                {isMultiSelect && (
                                  <div className={`mt-0.5 w-5 h-5 rounded-sm border flex items-center justify-center shrink-0 transition-all ${isSelected ? 'bg-slate-800 border-slate-800 text-white' : 'border-slate-300 bg-white'}`}>
                                    {isSelected && <Check size={12} strokeWidth={3} />}
                                  </div>
                                )}
                                <span className="flex-1">{s}</span>
                            </li>
                          );
                      })}
                   </ul>

                   {isMultiSelect && (
                     <div className="p-4 bg-slate-50 border-t border-slate-200">
                       <button
                         type="button"
                         onClick={handleApplySelected}
                         disabled={selectedSuggestions.length === 0}
                         className="w-full py-3 bg-slate-900 hover:bg-slate-800 disabled:bg-slate-300 text-white text-xs font-bold uppercase tracking-widest rounded-sm transition-all"
                       >
                         Gunakan {selectedSuggestions.length} Pilihan
                       </button>
                     </div>
                   )}
              </div>
          )}
      </div>
    );
  };

  return (
    <form onSubmit={handleSubmit} className="bg-white border border-slate-200 p-8 md:p-12 max-w-4xl mx-auto space-y-8 animate-fade-in-up delay-100 shadow-sm">

      {/* API Key Configuration */}
      <div className="bg-slate-50 text-slate-800 rounded-sm p-6 border border-slate-200">
        <div className="flex flex-col md:flex-row md:items-center gap-6">
          <div className="flex-1">
             <label className="text-xs font-bold text-slate-500 uppercase tracking-widest mb-2 block flex items-center gap-2">
               Konfigurasi: Gemini API Key
             </label>
             <div className="relative">
               <input 
                 type={showApiKey ? "text" : "password"} 
                 value={apiKey} 
                 onChange={handleApiKeyChange}
                 placeholder="Tempel API Key di sini..." 
                 className="w-full bg-white border border-slate-300 focus:border-slate-500 rounded-sm px-4 py-3 text-sm font-mono text-slate-700 placeholder:text-slate-300 outline-none transition-all"
               />
             </div>
          </div>
          <div className="flex items-center gap-4 shrink-0">
             <button 
                 type="button"
                 onClick={() => setShowApiKey(!showApiKey)}
                 className="text-slate-400 hover:text-slate-800 transition-colors"
                 title={showApiKey ? "Sembunyikan" : "Tampilkan"}
               >
                 {showApiKey ? <EyeOff size={20} /> : <Eye size={20} />}
             </button>
             <div className="h-8 w-px bg-slate-200"></div>
             <a 
              href="https://aistudio.google.com/app/apikey" 
              target="_blank" 
              rel="noreferrer" 
              className="px-5 py-2.5 bg-slate-900 text-white text-xs font-bold rounded-sm hover:bg-slate-800 transition-colors uppercase tracking-wide"
