  const [loadingField, setLoadingField] = useState<'cp' | 'tp' | 'materi' | null>(null);
  const [selectedSuggestions, setSelectedSuggestions] = useState<string[]>([]);

  // Load API Key from LocalStorage on mount
  useEffect(() => {
    const savedKey = localStorage.getItem('gemini_api_key');
    if (savedKey) setApiKey(savedKey);
  }, []);

  // Update meetings array when count changes
  useEffect(() => {
    setFormData(prev => {
      const currentCount = prev.meetings.length;
      const targetCount = prev.meetingCount;

      if (currentCount === targetCount) return prev;

      let newMeetings = [...prev.meetings];
      if (targetCount > currentCount) {
        for (let i = currentCount + 1; i <= targetCount; i++) {
          newMeetings.push({ meetingNumber: i, pedagogy: PedagogicalPractice.InkuiriDiscovery });
        }
      } else {
        newMeetings = newMeetings.slice(0, targetCount);
      }
      return { ...prev, meetings: newMeetings };
    });
  }, [formData.meetingCount]);

  const handleApiKeyChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const val = e.target.value;
    setApiKey(val);
    localStorage.setItem('gemini_api_key', val);
  };

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement | HTMLTextAreaElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  const handleDimensionChange = (dim: GraduateDimension) => {
    setFormData(prev => {
      const exists = prev.dimensions.includes(dim);
      if (exists) {
        return { ...prev, dimensions: prev.dimensions.filter(d => d !== dim) };
      } else {
        return { ...prev, dimensions: [...prev.dimensions, dim] };
      }
    });
  };

  const handlePedagogyChange = (index: number, value: PedagogicalPractice) => {
    const newMeetings = [...formData.meetings];
    newMeetings[index].pedagogy = value;
    setFormData(prev => ({ ...prev, meetings: newMeetings }));
  };

  const handleGetSuggestion = async (field: 'cp' | 'tp' | 'materi') => {
    if (!apiKey) {
      alert("Mohon isi Google API Key terlebih dahulu di bagian atas form.");
      return;
    }

    setLoadingField(field);
    setSuggestions([]);
    setSelectedSuggestions([]); // Reset selections
    setActiveField(null);

    // Determine context for the suggestion
    let context = "";
    if (field === 'tp') {
        context = formData.cp;
    } else if (field === 'materi') {
        context = `CP: ${formData.cp}. TP: ${formData.tp}`;
    }

    const opts = await getFieldSuggestions(field, formData.subject, formData.classLevel, apiKey, context);

    setSuggestions(opts);
    setActiveField(field);
    setLoadingField(null);
  };

  const handleSelectSuggestion = (val: string) => {
    if (activeField) {
        setFormData(prev => ({ ...prev, [activeField]: val }));
        setActiveField(null);
        setSuggestions([]);
        setSelectedSuggestions([]);
    }
  };

  const handleToggleSuggestion = (val: string) => {
    setSelectedSuggestions(prev => {
      if (prev.includes(val)) {
        return prev.filter(item => item !== val);
      } else {
        return [...prev, val];
      }
    });
  };

  const handleApplySelected = () => {
    if (activeField && selectedSuggestions.length > 0) {
      const joinedValue = selectedSuggestions.join('\n');
      setFormData(prev => ({ ...prev, [activeField]: joinedValue }));
      setActiveField(null);
      setSuggestions([]);
      setSelectedSuggestions([]);
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!apiKey) {
      alert("Mohon isi Google API Key terlebih dahulu.");
      return;
    }
    onSubmit(formData, apiKey);
  };

  // --- Styles Constants for Futuristic UI ---
  const SectionTitle = ({ title, icon: Icon }: { title: string, icon: any }) => (
    <div className="mb-8 mt-12 pb-4 border-b border-cyan-500/30 flex items-center justify-between">
      <div className="flex items-center gap-3">
        <div className="p-2 bg-cyan-950 rounded-lg border border-cyan-500/30 shadow-[0_0_10px_rgba(6,182,212,0.2)]">
          <Icon size={18} className="text-cyan-400" />
        </div>
        <h3 className="text-lg font-tech font-bold text-cyan-50 tracking-wider uppercase">{title}</h3>
      </div>
      <div className="h-1 w-20 bg-gradient-to-r from-cyan-500 to-transparent rounded-full"></div>
    </div>
  );

  const InputLabel = ({ label, required }: { label: string, required?: boolean }) => (
    <label className="block text-[10px] font-bold text-cyan-200/70 mb-2 uppercase tracking-widest">
      {label} {required && <span className="text-fuchsia-400">*</span>}
    </label>
  );

  // Futuristic Input Styling
  const InputClasses = "w-full px-4 py-3 bg-slate-950/50 border border-slate-700 rounded-lg text-sm font-medium text-cyan-50 placeholder:text-slate-600 focus:border-cyan-500 focus:ring-1 focus:ring-cyan-500 focus:shadow-[0_0_15px_rgba(6,182,212,0.3)] outline-none transition-all duration-300 backdrop-blur-sm";
  const SelectClasses = "w-full px-4 py-3 bg-slate-950/50 border border-slate-700 rounded-lg text-sm font-medium text-cyan-50 focus:border-cyan-500 focus:ring-1 focus:ring-cyan-500 outline-none appearance-none cursor-pointer transition-all duration-300 hover:border-cyan-500/50 backdrop-blur-sm";

  const renderSuggestionInput = (field: 'cp' | 'tp' | 'materi', label: string, rows: number, placeholder: string) => {
    const isMultiSelect = field === 'tp' || field === 'materi';

    return (
      <div className="relative group space-y-2 p-6 bg-slate-900/40 border border-white/5 rounded-xl hover:border-cyan-500/30 transition-all duration-300">
          <div className="flex justify-between items-center mb-1">
               <InputLabel label={label} required />
               <button 
                  type="button" 
                  onClick={() => handleGetSuggestion(field)}
                  disabled={loadingField === field}
                  className="px-3 py-1.5 bg-transparent border border-cyan-500/30 hover:border-cyan-400 hover:bg-cyan-500/10 text-cyan-400 rounded-md text-[10px] font-bold tracking-wider uppercase transition-all flex items-center gap-2 shadow-sm"
               >
                  {loadingField === field ? <Loader2 size={12} className="animate-spin" /> : <Sparkles size={12} />}
                  {loadingField === field ? 'Processing...' : 'AI Suggestion'}
               </button>
          </div>
          <div className="relative">
            <textarea 
                required 
                name={field} 
                value={formData[field]} 
                onChange={handleChange} 
                rows={rows} 
                className={`${InputClasses} resize-none leading-relaxed`}
                placeholder={placeholder} 
            />
            {/* Corner Accent */}
            <div className="absolute -bottom-1 -right-1 w-3 h-3 border-r border-b border-cyan-500/50 rounded-br pointer-events-none"></div>
          </div>

          {/* Dropdown Suggestions */}
          {activeField === field && suggestions.length > 0 && (
              <div className="absolute z-30 left-0 right-0 w-full bg-slate-900 border border-cyan-500/30 shadow-2xl shadow-cyan-900/20 rounded-xl mt-2 overflow-hidden animate-fade-in-up backdrop-blur-xl">
                   <div className="px-4 py-3 bg-cyan-950/50 border-b border-white/5 flex justify-between items-center">
                      <span className="text-[10px] font-bold text-cyan-400 uppercase tracking-widest flex items-center gap-2">
                        <Activity size={12} />
                        {isMultiSelect ? 'Select Multiple' : 'Select One'}
                      </span>
                      <button type="button" onClick={() => setActiveField(null)} className="text-slate-500 hover:text-fuchsia-400 transition">
                          <X size={16} />
                      </button>
                   </div>

                   <ul className="max-h-72 overflow-y-auto custom-scrollbar">
                      {suggestions.map((s, idx) => {
                          const isSelected = selectedSuggestions.includes(s);
                          return (
                            <li 
                                key={idx} 
                                onClick={() => isMultiSelect ? handleToggleSuggestion(s) : handleSelectSuggestion(s)} 
                                className={`px-5 py-4 text-sm border-b border-white/5 last:border-0 cursor-pointer transition-all flex items-start gap-4 leading-relaxed ${
                                  isSelected ? 'bg-cyan-900/20 text-cyan-300' : 'hover:bg-white/5 text-slate-400 hover:text-cyan-100'
                                }`}
                            >
                                {isMultiSelect && (
                                  <div className={`mt-0.5 w-5 h-5 rounded border flex items-center justify-center shrink-0 transition-all ${isSelected ? 'bg-cyan-500 border-cyan-500 text-black' : 'border-slate-600 bg-transparent'}`}>
                                    {isSelected && <Check size={12} strokeWidth={3} />}
                                  </div>
                                )}
                                <span className="flex-1">{s}</span>
                            </li>
                          );
                      })}
                   </ul>

                   {isMultiSelect && (
                     <div className="p-4 border-t border-white/5 bg-slate-900/80">
                       <button
                         type="button"
                         onClick={handleApplySelected}
                         disabled={selectedSuggestions.length === 0}
                         className="w-full py-3 bg-gradient-to-r from-cyan-600 to-blue-600 hover:from-cyan-500 hover:to-blue-500 text-white text-xs font-bold uppercase tracking-widest rounded-lg transition-all shadow-[0_0_15px_rgba(6,182,212,0.4)] disabled:opacity-50 disabled:shadow-none"
                       >
                         Confirm {selectedSuggestions.length} Selection
                       </button>
                     </div>
                   )}
              </div>
          )}
      </div>
    );
  };

  return (
    <form onSubmit={handleSubmit} className="bg-slate-900/60 backdrop-blur-md border border-white/10 p-8 md:p-12 max-w-5xl mx-auto rounded-2xl shadow-2xl relative overflow-hidden">

      {/* Decorative Elements */}
      <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-transparent via-cyan-500 to-transparent opacity-50"></div>

      {/* API Key Configuration */}
      <div className="bg-slate-950/80 rounded-xl p-6 border border-white/5 mb-10 relative group">
        <div className="absolute -inset-[1px] bg-gradient-to-r from-cyan-500/20 to-purple-500/20 rounded-xl blur opacity-0 group-hover:opacity-100 transition duration-1000"></div>
        <div className="flex flex-col md:flex-row md:items-center gap-6 relative z-10">
          <div className="flex-1">
             <label className="text-[10px] font-bold text-cyan-400 uppercase tracking-widest mb-2 block flex items-center gap-2">
               <span className="w-1.5 h-1.5 rounded-full bg-cyan-400 animate-pulse"></span>
               System Authorization: Gemini API Key
             </label>
             <div className="relative">
               <input 
                 type={showApiKey ? "text" : "password"} 
                 value={apiKey} 
                 onChange={handleApiKeyChange}
                 placeholder="Paste Key Here..." 
                 className="w-full bg-black/50 border border-slate-700 focus:border-cyan-500 rounded-lg px-4 py-3 text-sm font-mono text-cyan-300 placeholder:text-slate-600 outline-none transition-all"
               />
             </div>
          </div>
          <div className="flex items-center gap-4 shrink-0">
             <button 
                 type="button"
                 onClick={() => setShowApiKey(!showApiKey)}
                 className="text-slate-500 hover:text-cyan-400 transition-colors"
               >
                 {showApiKey ? <EyeOff size={20} /> : <Eye size={20} />}
             </button>
             <div className="h-8 w-px bg-slate-800"></div>
             <a 
              href="https://aistudio.google.com/app/apikey" 
              target="_blank" 
              rel="noreferrer" 
              className="px-5 py-2.5 bg-transparent border border-cyan-500/30 text-cyan-400 text-xs font-bold rounded-lg hover:bg-cyan-500/10 hover:border-cyan-400 transition-all uppercase tracking-wide"
             >
               Create Key
             </a>
          </div>
        </div>
      </div>

      {/* Identitas Guru & Sekolah */}
      <section>
        <SectionTitle title="1. Informasi Pendidik" icon={User} />
        <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
          <div className="opacity-50 pointer-events-none">
            <InputLabel label="Nama Satuan Pendidikan" />
            <input type="text" value="SDN Pekayon 09" disabled className={InputClasses} />
          </div>
          <div className="hidden md:block"></div>

          <div>
            <InputLabel label="Nama Guru" required />
            <input required name="teacherName" value={formData.teacherName} onChange={handleChange} className={InputClasses} placeholder="Nama Lengkap & Gelar" />
          </div>
          <div>
            <InputLabel label="NIP Guru" required />
            <input required name="teacherNIP" value={formData.teacherNIP} onChange={handleChange} className={InputClasses} placeholder="NIP tanpa spasi" />
          </div>

          <div>
            <InputLabel label="Nama Kepala Sekolah" />
            <input name="principalName" value={formData.principalName} onChange={handleChange} className={InputClasses} />
          </div>
          <div>
            <InputLabel label="NIP Kepala Sekolah" />
            <input name="principalNIP" value={formData.principalNIP} onChange={handleChange} className={InputClasses} />
          </div>
        </div>
      </section>

      {/* Informasi Pembelajaran */}
      <section>
        <SectionTitle title="2. Kurikulum & Materi" icon={BookOpen} />
        <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-8">
          <div className="relative">
            <InputLabel label="Kelas" />
            <div className="relative">
              <select name="classLevel" value={formData.classLevel} onChange={handleChange} className={SelectClasses}>
                {Object.values(ClassLevel).map(c => <option key={c} value={c}>Kelas {c}</option>)}
              </select>
              <ChevronDown className="absolute right-4 top-1/2 -translate-y-1/2 text-slate-500 pointer-events-none" size={16} />
            </div>
          </div>
          <div className="relative">
            <InputLabel label="Semester" />
            <div className="relative">
              <select name="semester" value={formData.semester} onChange={handleChange} className={SelectClasses}>
                {Object.values(Semester).map(s => <option key={s} value={s}>{s}</option>)}
              </select>
              <ChevronDown className="absolute right-4 top-1/2 -translate-y-1/2 text-slate-500 pointer-events-none" size={16} />
            </div>
          </div>
          <div className="relative">
            <InputLabel label="Mata Pelajaran" />
            <div className="relative">
              <select name="subject" value={formData.subject} onChange={handleChange} className={SelectClasses}>
                {Object.values(Subject).map(s => <option key={s} value={s}>{s}</option>)}
              </select>
              <ChevronDown className="absolute right-4 top-1/2 -translate-y-1/2 text-slate-500 pointer-events-none" size={16} />
            </div>
          </div>
        </div>

        {/* Suggestion Inputs */}
        <div className="space-y-6">
             {renderSuggestionInput('cp', 'Capaian Pembelajaran (CP)', 3, 'Tulis CP atau gunakan tombol AI...')}
             {renderSuggestionInput('tp', 'Tujuan Pembelajaran (TP)', 2, 'Tulis TP atau gunakan tombol AI...')}
             {renderSuggestionInput('materi', 'Materi Pelajaran', 2, 'Tulis Materi atau gunakan tombol AI...')}
        </div>
      </section>

      {/* Detil Pertemuan */}
      <section>
        <SectionTitle title="3. Strategi Pertemuan" icon={Calendar} />
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6 mb-8">
           <div className="relative">
            <InputLabel label="Jumlah Pertemuan" />
            <div className="relative">
              <select name="meetingCount" value={formData.meetingCount} onChange={(e) => setFormData({...formData, meetingCount: parseInt(e.target.value)})} className={SelectClasses}>
                {[1, 2, 3, 4, 5, 6, 7, 8].map(n => <option key={n} value={n}>{n} Pertemuan</option>)}
              </select>
              <ChevronDown className="absolute right-4 top-1/2 -translate-y-1/2 text-slate-500 pointer-events-none" size={16} />
            </div>
           </div>
           <div>
            <InputLabel label="Durasi Total" />
            <input name="duration" value={formData.duration} onChange={handleChange} className={InputClasses} placeholder="Contoh: 2 x 35 menit" />
           </div>
        </div>

        <div className="space-y-4">
           <InputLabel label="Model Pembelajaran per Pertemuan" />
           {formData.meetings.map((meeting, idx) => (
             <div key={idx} className="flex items-center gap-4 p-4 rounded-xl border border-white/5 bg-slate-900/50 hover:border-cyan-500/30 transition-all">
                <span className="text-[10px] font-bold text-cyan-400 uppercase tracking-widest w-28">Pertemuan {meeting.meetingNumber}</span>
                <div className="h-6 w-px bg-white/10"></div>
                <div className="relative flex-1">
                  <select 
                    value={meeting.pedagogy} 
                    onChange={(e) => handlePedagogyChange(idx, e.target.value as PedagogicalPractice)}
                    className="w-full bg-transparent text-sm font-medium text-slate-200 outline-none cursor-pointer appearance-none"
                  >
                    {Object.values(PedagogicalPractice).map(p => <option key={p} value={p}>{p}</option>)}
                  </select>
                  <ChevronDown className="absolute right-0 top-1/2 -translate-y-1/2 text-slate-500 pointer-events-none" size={14} />
                </div>
             </div>
           ))}
        </div>
      </section>

      {/* Profil Lulusan - Simplified Checkbox Style */}
      <section>
        <SectionTitle title="4. Profil Lulusan" icon={BrainCircuit} />
        <div className="bg-slate-900/50 p-6 rounded-xl border border-white/5">
           <InputLabel label="Pilih Dimensi yang Relevan" />
           <div className="grid grid-cols-1 md:grid-cols-2 gap-y-3 gap-x-8 mt-4">
             {Object.values(GraduateDimension).map((dim) => (
               <label key={dim} className="flex items-center gap-3 cursor-pointer group hover:bg-white/5 p-2 rounded transition-colors">
                  <div className="relative flex items-center">
                    <input 
                      type="checkbox" 
                      checked={formData.dimensions.includes(dim)} 
                      onChange={() => handleDimensionChange(dim)} 
                      className="peer h-5 w-5 cursor-pointer appearance-none rounded border border-slate-600 bg-slate-950 checked:border-cyan-500 checked:bg-cyan-500 transition-all" 
                    />
                    <Check 
                      size={14} 
                      className="absolute left-1/2 top-1/2 -translate-x-1/2 -translate-y-1/2 text-black opacity-0 peer-checked:opacity-100 pointer-events-none transition-opacity" 
                      strokeWidth={3}
                    />
                  </div>
                  <span className={`text-sm transition-colors ${formData.dimensions.includes(dim) ? 'text-cyan-300 font-medium' : 'text-slate-400 group-hover:text-slate-200'}`}>
                    {dim}
                  </span>
               </label>
             ))}
           </div>
        </div>
      </section>

      {/* Submit Button - Transparent Style */}
      <div className="pt-8">
        <button 
          type="submit" 
          disabled={isLoading}
          className="w-full bg-transparent border-2 border-cyan-500/50 hover:border-cyan-400 hover:bg-cyan-500/10 text-cyan-400 font-tech font-bold text-base uppercase tracking-[0.2em] py-5 rounded-lg shadow-[0_0_15px_rgba(6,182,212,0.1)] hover:shadow-[0_0_30px_rgba(6,182,212,0.3)] disabled:opacity-50 disabled:cursor-not-allowed flex justify-center items-center gap-4 transition-all duration-300 backdrop-blur-sm group"
        >
          {isLoading ? (
            <>
              <Loader2 className="animate-spin text-cyan-400" size={24} />
              <span className="text-cyan-400/80">Processing Data...</span>
            </>
          ) : (
            <>
              <span>Initiate Generation</span>
              <Sparkles className="text-cyan-400 group-hover:scale-125 transition-transform" size={20} fill="currentColor" />
            </>
          )}
        </button>
      </div>
    </form>
  );
};

export default InputForm;

import React, { useRef } from 'react';
import { RPMResult } from '../types';
import { Copy, Download, ArrowLeft } from 'lucide-react';
// @ts-ignore
import html2pdf from 'html2pdf.js';

interface RPMPreviewProps {
  data: RPMResult;
  onReset: () => void;
}

const RPMPreview: React.FC<RPMPreviewProps> = ({ data, onReset }) => {
  const contentRef = useRef<HTMLDivElement>(null);

  const handleCopyToDocs = async () => {
    if (!contentRef.current) return;

    try {
      const blob = new Blob([contentRef.current.innerHTML], { type: 'text/html' });
      // @ts-ignore
      const clipboardItem = new ClipboardItem({ 'text/html': blob });
      // @ts-ignore
      await navigator.clipboard.write([clipboardItem]);

      const confirm = window.confirm("Konten RPM telah disalin ke Clipboard! \n\nSekarang kami akan membuka Google Docs baru. \nSilakan tekan 'Ctrl+V' (Paste) di halaman Google Docs yang terbuka untuk melihat hasilnya.");

      if(confirm) {
        window.open('https://docs.google.com/document/create', '_blank');
      }
    } catch (err) {
      console.error(err);
      alert('Gagal menyalin otomatis. Silakan seleksi manual dan salin.');
    }
  };

  const handleDownloadPDF = () => {
    const element = contentRef.current;

    // Konfigurasi Margin: 1cm (10mm) untuk semua sisi
    const opt = {
      margin:       10, 
      filename:     `RPM_${data.subject}_Kelas${data.classLevel}.pdf`,
      image:        { type: 'jpeg' as const, quality: 0.98 },
      html2canvas:  { scale: 2, useCORS: true }, 
      jsPDF:        { unit: 'mm', format: 'a4', orientation: 'portrait' as const }
    };

    // Generate PDF dengan Footer Custom
    html2pdf()
      .from(element)
      .set(opt)
      .toPdf()
      .get('pdf')
      .then((pdf: any) => {
        const totalPages = pdf.internal.getNumberOfPages();
        const pageWidth = pdf.internal.pageSize.getWidth();
        const pageHeight = pdf.internal.pageSize.getHeight();

        for (let i = 1; i <= totalPages; i++) {
          pdf.setPage(i);
          pdf.setFontSize(8);
          pdf.setTextColor(150); // Abu-abu halus

          // Text Footer Kiri: Informasi Dokumen
          const leftText = `RPM Kelas ${data.classLevel} | ${data.subject}`;
          pdf.text(leftText, 10, pageHeight - 5); 

          // Text Footer Kanan: Nomor Halaman
          const rightText = `Hal. ${i} dari ${totalPages}`;
          const textWidth = pdf.getStringUnitWidth(rightText) * pdf.internal.getFontSize() / pdf.internal.scaleFactor;
          pdf.text(rightText, pageWidth - 10 - textWidth, pageHeight - 5); 
        }

        // Save manually here to avoid Promise chaining issues in TypeScript
        pdf.save(opt.filename);
      });
  };

  const TARGET_TEACHER = "Teguh Firmansyah Apriliana, S.Pd";
  const SIGNATURE_URL = "https://i.ibb.co.com/KctJSrRC/ttd-gue.png";
  const shouldShowSignature = data.teacherName.trim() === TARGET_TEACHER;

  return (
    <div className="max-w-5xl mx-auto pb-20">
      {/* Action Bar - Futuristic Transparent */}
      <div className="sticky top-4 z-50 flex flex-wrap gap-3 justify-between items-center bg-slate-900/60 backdrop-blur-xl border border-cyan-500/20 p-4 rounded-xl shadow-2xl mb-8 no-print text-cyan-50">
        <button onClick={onReset} className="flex items-center gap-2 text-slate-400 hover:text-cyan-400 font-bold transition uppercase text-xs tracking-wider">
          <ArrowLeft size={16} /> Edit Data
        </button>
        <div className="flex gap-3">
          <button onClick={handleCopyToDocs} className="flex items-center gap-2 bg-transparent border border-white/10 hover:border-cyan-400/50 hover:bg-cyan-500/10 px-4 py-2 rounded-lg font-bold text-xs uppercase tracking-wide transition text-cyan-100">
            <Copy size={16} />
            <span className="hidden sm:inline">Salin & Buka G-Docs</span>
          </button>
          <button onClick={handleDownloadPDF} className="flex items-center gap-2 bg-cyan-600/20 border border-cyan-500/50 text-cyan-300 hover:bg-cyan-600/40 px-4 py-2 rounded-lg font-bold text-xs uppercase tracking-wide transition shadow-[0_0_15px_rgba(6,182,212,0.2)]">
            <Download size={16} />
            <span className="hidden sm:inline">Download PDF</span>
          </button>
        </div>
      </div>

      {/* Document Content - Remains Formal White Paper */}
      <div id="rpm-content" ref={contentRef} className="bg-white p-8 md:p-12 shadow-2xl min-h-screen text-slate-900 border border-slate-200">
