const getAI = (apiKey: string) => new GoogleGenAI({ apiKey });

const generatedContentSchema: Schema = {
  type: Type.OBJECT,
  properties: {
    studentCharacteristics: { type: Type.STRING, description: "HTML Unordered List (<ul><li>...</li></ul>)." },
    crossDisciplinary: { type: Type.STRING, description: "HTML Unordered List (<ul><li>...</li></ul>)." },
    topics: { type: Type.STRING, description: "HTML Unordered List (<ul><li>...</li></ul>)." },
