    environment: { type: Type.STRING, description: "HTML Unordered List (<ul><li>...</li></ul>)." },
    digitalTools: { type: Type.STRING, description: "HTML Unordered List (<ul><li>...</li></ul>)." },
    learningExperiences: {
      type: Type.OBJECT,
      properties: {
        memahami: { type: Type.STRING, description: "HTML Ordered List (<ol><li>...</li></ol>)." },
        mengaplikasi: { type: Type.STRING, description: "HTML Ordered List (<ol><li>...</li></ol>)." },
        refleksi: { type: Type.STRING, description: "HTML Ordered List (<ol><li>...</li></ol>)." },
      },
      required: ["memahami", "mengaplikasi", "refleksi"]
    },
    assessments: {
      type: Type.OBJECT,
      properties: {
        initial: { type: Type.STRING, description: "HTML Unordered List (<ul><li>...</li></ul>)." },
        process: { type: Type.STRING, description: "HTML Unordered List (<ul><li>...</li></ul>)." },
        final: { type: Type.STRING, description: "HTML Unordered List (<ul><li>...</li></ul>)." },
      },
      required: ["initial", "process", "final"]
    },
    rubric: {
      type: Type.OBJECT,
      properties: {
        title: { type: Type.STRING },
        rows: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              aspect: { type: Type.STRING },
              score4: { type: Type.STRING },
              score3: { type: Type.STRING },
              score2: { type: Type.STRING },
              score1: { type: Type.STRING },
            },
            required: ["aspect", "score4", "score3", "score2", "score1"]
          }
        }
      },
      required: ["title", "rows"]
    }
  },
  required: ["studentCharacteristics", "crossDisciplinary", "topics", "partnerships", "environment", "digitalTools", "learningExperiences", "assessments", "rubric"]
};

export const generateRPM = async (data: FormData, apiKey: string): Promise<GeneratedContent> => {
  if (!apiKey) throw new Error("API Key wajib diisi.");

  const ai = getAI(apiKey);
  const pedagogies = data.meetings.map(m => `Pertemuan ${m.meetingNumber}: ${m.pedagogy}`).join(", ");
  const dimensions = data.dimensions.join(", ");

  const prompt = `
    Bertindaklah sebagai ahli kurikulum SD Indonesia. Buatlah konten Rencana Pembelajaran Mendalam (RPM) untuk SDN Pekayon 09.

    Data Input:
    - Kelas: ${data.classLevel}
    - Mapel: ${data.subject}
    - Materi: ${data.materi}
    - CP: ${data.cp}
    - TP: ${data.tp}
    - Dimensi Profil Lulusan: ${dimensions}
    - Praktik Pedagogis: ${pedagogies}

    Tugas:
    Lengkapi bagian rencana pembelajaran dengan bahasa Indonesia formal.
    Gunakan tag HTML <ul>/<li> untuk list dan <ol>/<li> untuk langkah berurutan.

    Konten khusus: 
    - Pengalaman Belajar 'Mengaplikasi' harus SANGAT detail mengikuti sintaks pedagogi: ${pedagogies}.
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-pro-preview",
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: generatedContentSchema,
      }
    });

    return JSON.parse(response.text || "{}") as GeneratedContent;
  } catch (error) {
    console.error("Error generating RPM:", error);
    throw error;
  }
};

const getPhase = (classLevel: string): 'FaseA' | 'FaseB' | 'FaseC' => {
  if (classLevel === ClassLevel.Kelas1 || classLevel === ClassLevel.Kelas2) return 'FaseA';
  if (classLevel === ClassLevel.Kelas3 || classLevel === ClassLevel.Kelas4) return 'FaseB';
  return 'FaseC';
};

export const getFieldSuggestions = async (
  field: 'cp' | 'tp' | 'materi',
  subject: Subject,
  classLevel: ClassLevel,
  apiKey: string,
  currentContext: string = "" 
): Promise<string[]> => {
    if (!apiKey) return ["Harap masukkan API Key."];

    const ai = getAI(apiKey);
    const phase = getPhase(classLevel);
    const officialCP = CP_REF[subject]?.[phase];

    let prompt = "";
    if (field === 'cp') {
      prompt = `Berikan 5 variasi Capaian Pembelajaran (CP) untuk ${subject} Kelas ${classLevel} SD. Referensi resmi: "${officialCP || 'Gunakan kurikulum merdeka standar'}".`;
    } else if (field === 'tp') {
      prompt = `Berdasarkan CP: "${currentContext}", berikan 5 Tujuan Pembelajaran (TP) yang spesifik dan terukur.`;
    } else if (field === 'materi') {
      prompt = `Berdasarkan CP/TP: "${currentContext}", berikan 5 topik materi pokok yang relevan.`;
    }

    prompt += ` Output wajib JSON: { "options": ["opsi 1", "opsi 2", ...] }`;

    try {
        const response = await ai.models.generateContent({
            model: "gemini-3-flash-preview",
            contents: prompt,
            config: {
                responseMimeType: "application/json",
                responseSchema: {
                    type: Type.OBJECT,
                    properties: {
                        options: { type: Type.ARRAY, items: { type: Type.STRING } }
                    }
                }
            }
        });
        const result = JSON.parse(response.text || "{}");
        return result.options || [];
    } catch (e) {
        console.error(e);
        return ["Gagal mengambil saran."];
    }
};

