        </div>
      </section>

      <div className="pt-12">
        <button type="submit" disabled={isLoading} className="w-full bg-purple-600 hover:bg-purple-700 text-white font-tech font-bold py-5 rounded-lg shadow-lg flex justify-center items-center gap-4 transition-all uppercase tracking-widest disabled:opacity-50">
          {isLoading ? <Loader2 className="animate-spin" size={24} /> : <>Generate RPM <Sparkles size={20} /></>}
        </button>
      </div>
    </form>
  );
};

export default InputForm;

import React, { useRef } from 'react';
import { RPMResult } from '../types';
import { Copy, Download, ArrowLeft } from 'lucide-react';
// @ts-ignore
import html2pdf from 'html2pdf.js';

interface RPMPreviewProps {
  data: RPMResult;
  onReset: () => void;
}

const RPMPreview: React.FC<RPMPreviewProps> = ({ data, onReset }) => {
  const contentRef = useRef<HTMLDivElement>(null);

  const formatDate = (dateString: string) => {
    if (!dateString) return "-";
    const date = new Date(dateString);
    return date.toLocaleDateString('id-ID', { day: 'numeric', month: 'long', year: 'numeric' });
  };

  const handleCopyToDocs = async () => {
    if (!contentRef.current) return;
    try {
      const blob = new Blob([contentRef.current.innerHTML], { type: 'text/html' });
      // @ts-ignore
      const clipboardItem = new ClipboardItem({ 'text/html': blob });
      // @ts-ignore
      await navigator.clipboard.write([clipboardItem]);
      alert("Disalin ke Clipboard! Silakan Paste (Ctrl+V) di Google Docs.");
      window.open('https://docs.google.com/document/create', '_blank');
    } catch (err) { alert('Gagal menyalin otomatis.'); }
  };

  const handleDownloadPDF = () => {
    const element = contentRef.current;
    const opt = {
      margin: 10, 
      filename: `RPM_${data.subject}_Kelas${data.classLevel}.pdf`,
      image: { type: 'jpeg', quality: 0.98 },
      html2canvas: { scale: 2, useCORS: true }, 
      jsPDF: { unit: 'mm', format: 'a4', orientation: 'portrait' }
