        </div>
      </div>

      <div ref={contentRef} className="bg-white p-12 shadow-2xl min-h-screen border border-slate-200" style={{ color: '#000', fontSize: '10pt', lineHeight: '1.5' }}>
        <div className="flex justify-between items-center border-b-4 border-black pb-4 mb-8">
            <img src="https://i.ibb.co.com/1fQ81J6v/LOGO-PEKAYON-09.jpg" crossOrigin="anonymous" style={{ height: '70px' }} />
            <div className="text-center flex-1">
