            <img src="https://i.ibb.co.com/fz9ttjq6/Logo-of-Ministry-of-Education-and-Culture-of-Republic-of-Indonesia-svg.png" crossOrigin="anonymous" style={{ height: '70px' }} />
        </div>

        <h2 className="font-bold uppercase border-b-2 border-black mb-4">1. Identitas</h2>
        <table className="w-full border-2 border-black mb-6">
          <tbody>
