export const getFieldSuggestions = async (
  field: 'cp' | 'tp' | 'materi',
  subject: Subject,
  classLevel: ClassLevel,
  apiKey: string,
  currentContext: string = "" 
): Promise<string[]> => {
    if (!apiKey) return ["Harap masukkan API Key."];
    const ai = getAI(apiKey);
    const phase = getPhase(classLevel);
    const officialCP = CP_REF[subject]?.[phase];

    let promptContext = "";

    // Spesifik untuk Koding dan KA Fase C (Kelas 5 & 6)
    if (subject === Subject.KodingDanKA && phase === 'FaseC') {
        promptContext = `
            Ini adalah mata pelajaran Koding dan Kecerdasan Artifisial. 
            Gunakan referensi kurikulum berikut: ${KODING_KA_FaseC_REF}
            ${field === 'cp' ? 'Gunakan CP Fase C: ' + officialCP : ''}
            ${field === 'materi' ? 'Sajikan 5 pilihan materi dari daftar 14 materi tersebut.' : ''}
            ${field === 'tp' ? 'Sajikan 5 pilihan TP yang sesuai dengan materi yang dipilih atau dari daftar kurikulum tersebut.' : ''}
        `;
    } else {
        if (field === 'cp') {
            promptContext = officialCP ? `Referensi CP: "${officialCP}". Buat 5 variasi.` : `Buat 5 opsi CP Merdeka.`;
        } else if (field === 'tp') {
            promptContext = currentContext ? `Turunkan 5 TP dari: "${currentContext}".` : `Buat 5 TP relevan.`;
        } else if (field === 'materi') {
            promptContext = `Berdasarkan CP/TP: "${currentContext}", sarankan 5 materi pokok.`;
        }
