    const prompt = `Berikan 5 opsi ${field} untuk mapel ${subject} Kelas ${classLevel}. ${promptContext} Output JSON: { "options": [...] }`;

    try {
        const response = await ai.models.generateContent({
            model: "gemini-3-flash-preview",
