              <span className="text-[10px] font-bold text-slate-400 uppercase w-24">Pertemuan {m.meetingNumber}</span>
              <select 
                value={m.pedagogy} 
                onChange={(e) => handlePedagogyChange(idx, e.target.value as PedagogicalPractice)}
