// Helper: Get AI Instance dengan Prioritas Logic
// 1. Parameter (dari State React)
// 2. LocalStorage (User saved)
// 3. Environment Variable (process.env or import.meta.env)
const getAI = (providedKey?: string) => {
  let finalKey = providedKey;

  // Cek LocalStorage jika parameter kosong
  if (!finalKey || finalKey.trim() === '') {
    finalKey = localStorage.getItem('gemini_api_key') || '';
  }

  // Cek Environment Variable (Support process.env for Vercel & import.meta for Vite)
  if (!finalKey || finalKey.trim() === '') {
    // Check process.env first (injected by vite define)
    // We access properties directly to ensure replacement works
    const envKey = process.env.API_KEY || process.env.VITE_GEMINI_API_KEY;

    if (envKey) {
      finalKey = envKey;
    } else {
      // Fallback to standard Vite import.meta
      finalKey = (import.meta as any).env.VITE_GEMINI_API_KEY || '';
    }
  }

  // Jika tetap kosong, lempar error spesifik
  if (!finalKey || finalKey.trim() === '') {
    throw new Error("API_KEY_MISSING");
  }

  return new GoogleGenAI({ apiKey: finalKey });
};

